const FIREBASE = {
  apiKey: import.meta.env.VITE_FIREBASE_API_KEY || "",
  projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID || "msc-schedule-sim",
};
const FS_BASE = `https://firestore.googleapis.com/v1/projects/${FIREBASE.projectId}/databases/(default)/documents`;

// ── Authentication (Firebase Auth REST API) ─────────────────────────────────
const AUTH_BASE = "https://identitytoolkit.googleapis.com/v1";
const REQUIRE_AUTH = !["localhost", "127.0.0.1", ""].includes(window.location.hostname);

let _authToken = null;
let _authRefreshToken = null;
let _authTokenExpiry = 0;
let _authUser = null;
let _authRefreshPromise = null;

async function authSignIn(email, password) {
  const res = await fetch(`${AUTH_BASE}/accounts:signInWithPassword?key=${FIREBASE.apiKey}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ email, password, returnSecureToken: true }),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    const msg = err?.error?.message || "Authentication failed";
    throw new Error(msg === "EMAIL_NOT_FOUND" ? "Email not found" : msg === "INVALID_PASSWORD" ? "Incorrect password" : msg === "INVALID_LOGIN_CREDENTIALS" ? "Invalid email or password" : msg);
  }
  const data = await res.json();
  _authToken = data.idToken;
  _authRefreshToken = data.refreshToken;
  _authTokenExpiry = Date.now() + (parseInt(data.expiresIn) || 3600) * 1000 - 60000;
  _authUser = { email: data.email, localId: data.localId };
  try { sessionStorage.setItem("msc_auth", JSON.stringify({ token: _authToken, refreshToken: _authRefreshToken, expiry: _authTokenExpiry, user: _authUser })); } catch {}
  return _authUser;
}

async function authRefresh() {
  if (!_authRefreshToken) return null;
  if (_authRefreshPromise) return _authRefreshPromise;
  _authRefreshPromise = (async () => {
    try {
      const res = await fetch(`https://securetoken.googleapis.com/v1/token?key=${FIREBASE.apiKey}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ grant_type: "refresh_token", refresh_token: _authRefreshToken }),
      });
      if (!res.ok) { authSignOut(); return null; }
      const data = await res.json();
      _authToken = data.id_token;
      _authRefreshToken = data.refresh_token;
      _authTokenExpiry = Date.now() + (parseInt(data.expires_in) || 3600) * 1000 - 60000;
      try { sessionStorage.setItem("msc_auth", JSON.stringify({ token: _authToken, refreshToken: _authRefreshToken, expiry: _authTokenExpiry, user: _authUser })); } catch {}
      return _authToken;
    } catch { authSignOut(); return null; }
    finally { _authRefreshPromise = null; }
  })();
  return _authRefreshPromise;
}

async function getAuthToken() {
  if (!REQUIRE_AUTH) return null;
  if (_authToken && Date.now() < _authTokenExpiry) return _authToken;
  return authRefresh();
}

function authSignOut() {
  _authToken = null; _authRefreshToken = null; _authTokenExpiry = 0; _authUser = null;
  try { sessionStorage.removeItem("msc_auth"); } catch {}
}

function authLoadSession() {
  try {
    const raw = sessionStorage.getItem("msc_auth");
    if (!raw) return null;
    const s = JSON.parse(raw);
    if (!s.token || !s.refreshToken || !s.user) return null;
    _authToken = s.token; _authRefreshToken = s.refreshToken; _authTokenExpiry = s.expiry || 0; _authUser = s.user;
    return _authUser;
  } catch { return null; }
}

async function authChangePassword(newPassword) {
  const token = await getAuthToken();
  if (!token) throw new Error("Not authenticated");
  const res = await fetch(`${AUTH_BASE}/accounts:update?key=${FIREBASE.apiKey}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ idToken: token, password: newPassword, returnSecureToken: true }),
  });
  if (!res.ok) { const err = await res.json().catch(() => ({})); throw new Error(err?.error?.message || "Failed to change password"); }
  const data = await res.json();
  _authToken = data.idToken;
  _authRefreshToken = data.refreshToken;
  _authTokenExpiry = Date.now() + (parseInt(data.expiresIn) || 3600) * 1000 - 60000;
  try { sessionStorage.setItem("msc_auth", JSON.stringify({ token: _authToken, refreshToken: _authRefreshToken, expiry: _authTokenExpiry, user: _authUser })); } catch {}
}

async function authSendPasswordReset(email) {
  const res = await fetch(`${AUTH_BASE}/accounts:sendOobCode?key=${FIREBASE.apiKey}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ requestType: "PASSWORD_RESET", email }),
  });
  if (!res.ok) { const err = await res.json().catch(() => ({})); throw new Error(err?.error?.message || "Failed to send reset email"); }
}

const AUTH_ERROR_MAP = {
  EMAIL_EXISTS: "This email is already registered",
  WEAK_PASSWORD: "Password must be at least 6 characters",
  INVALID_EMAIL: "Please enter a valid email address",
  OPERATION_NOT_ALLOWED: "Account creation is currently disabled",
  TOO_MANY_ATTEMPTS_TRY_LATER: "Too many attempts — please wait and try again",
  MISSING_PASSWORD: "Password is required",
  MISSING_EMAIL: "Email is required",
};

function friendlyAuthError(rawMsg, fallback) {
  if (!rawMsg) return fallback;
  // Firebase error codes sometimes arrive with extra context (e.g. "WEAK_PASSWORD : ...")
  const code = rawMsg.split(/[\s:]/)[0];
  return AUTH_ERROR_MAP[code] || AUTH_ERROR_MAP[rawMsg] || fallback;
}

async function authCreateUser(email, password) {
  const res = await fetch(`${AUTH_BASE}/accounts:signUp?key=${FIREBASE.apiKey}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ email, password, returnSecureToken: false }),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    const msg = err?.error?.message || "";
    throw new Error(friendlyAuthError(msg, "Failed to create user"));
  }
  return await res.json();
}

// ─── Admin role system ──────────────────────────────────────────────────────
//
// Admins are stored in Firestore at `config/admins` as:
//   { emails: ["admin1@msc.com", "admin2@msc.com", ...] }
//
// The first admin MUST be added manually via the Firebase Console (bootstrap).
// After that, Firestore security rules should restrict writes to `config/admins`
// to existing admins only.
//
// IMPORTANT: This is CLIENT-SIDE UI gating only. Firebase Auth's `accounts:signUp`
// REST endpoint is publicly accessible and cannot be restricted by Firestore rules.
// Full enforcement requires a Cloud Function (Admin SDK) as a signup proxy, or
// disabling the signup endpoint entirely in Firebase Console.
//
// See ADMIN.md for deployment guidance.

/**
 * Load the admin email list from Firestore.
 * Returns an array of lowercase emails. Empty array if the doc is missing,
 * malformed, or unreachable (safe default: no admins).
 */
async function loadAdminList() {
  try {
    const data = await fsGet("config", "admins");
    if (!data || !Array.isArray(data.emails)) return [];
    return data.emails
      .filter(e => typeof e === "string" && e.trim().length > 0)
      .map(e => e.trim().toLowerCase());
  } catch {
    return [];
  }
}

/** Is the given email an admin according to the loaded admin list? */
function isEmailAdmin(email, adminEmails) {
  if (!email || !Array.isArray(adminEmails) || adminEmails.length === 0) return false;
  return adminEmails.includes(email.trim().toLowerCase());
}

// ── localStorage encryption (used by offline mode) ──────────────────────────
const ENCRYPT_LOCAL = typeof window !== "undefined" && window.crypto?.subtle;
let _encKeyPromise = null;

async function getEncKey() {
  if (_encKeyPromise) return _encKeyPromise;
  _encKeyPromise = (async () => {
    const raw = new TextEncoder().encode("msc-schedule-sim-local-" + (navigator.userAgent || "").slice(0, 50));
    const hash = await crypto.subtle.digest("SHA-256", raw);
    return crypto.subtle.importKey("raw", hash, "AES-GCM", false, ["encrypt", "decrypt"]);
  })();
  return _encKeyPromise;
}

async function encryptData(plaintext) {
  if (!ENCRYPT_LOCAL) return plaintext;
  try {
    const key = await getEncKey();
    const iv = crypto.getRandomValues(new Uint8Array(12));
    const encoded = new TextEncoder().encode(plaintext);
    const cipher = await crypto.subtle.encrypt({ name: "AES-GCM", iv }, key, encoded);
    const combined = new Uint8Array(iv.length + cipher.byteLength);
    combined.set(iv);
    combined.set(new Uint8Array(cipher), iv.length);
    return btoa(String.fromCharCode(...combined));
  } catch { return plaintext; }
}

async function decryptData(ciphertext) {
  if (!ENCRYPT_LOCAL) return ciphertext;
  try {
    if (!ciphertext.match(/^[A-Za-z0-9+/=]+$/)) return ciphertext; // not encrypted, return as-is
    const key = await getEncKey();
    const combined = Uint8Array.from(atob(ciphertext), c => c.charCodeAt(0));
    const iv = combined.slice(0, 12);
    const data = combined.slice(12);
    const decrypted = await crypto.subtle.decrypt({ name: "AES-GCM", iv }, key, data);
    return new TextDecoder().decode(decrypted);
  } catch { return ciphertext; } // decryption failed, return raw (might be unencrypted legacy data)
}

async function fsGet(collection, docId) {
  try {
    const token = await getAuthToken();
    const headers = token ? { Authorization: `Bearer ${token}` } : {};
    const res = await fetch(`${FS_BASE}/${collection}/${docId}?key=${FIREBASE.apiKey}`, { headers });
    if (res.status === 404) return null;
    if (!res.ok) return null;
    const doc = await res.json();
    const json = doc.fields?.data?.stringValue;
    return json ? JSON.parse(json) : null;
  } catch { return null; }
}

async function fsSet(collection, docId, data) {
  try {
    const token = await getAuthToken();
    const hdrs = { "Content-Type": "application/json" };
    if (token) hdrs.Authorization = `Bearer ${token}`;
    const res = await fetch(`${FS_BASE}/${collection}/${docId}?key=${FIREBASE.apiKey}`, {
      method: "PATCH",
      headers: hdrs,
      body: JSON.stringify({
        fields: {
          data: { stringValue: JSON.stringify(data) },
          updatedAt: { stringValue: new Date().toISOString() },
        },
      }),
    });
    return res.ok;
  } catch { return false; }
}

async function fsList(collection) {
  try {
    const token = await getAuthToken();
    const headers = token ? { Authorization: `Bearer ${token}` } : {};
    const res = await fetch(`${FS_BASE}/${collection}?key=${FIREBASE.apiKey}&pageSize=100`, { headers });
    if (!res.ok) return [];
    const body = await res.json();
    return (body.documents || []).map(doc => {
      const id = doc.name.split("/").pop();
      const data = doc.fields?.data?.stringValue;
      const updatedAt = doc.fields?.updatedAt?.stringValue || "";
      return { id, updatedAt, data: data ? JSON.parse(data) : null };
    });
  } catch { return []; }
}

async function fsDelete(collection, docId) {
  try {
    const token = await getAuthToken();
    const headers = token ? { Authorization: `Bearer ${token}` } : {};
    const res = await fetch(`${FS_BASE}/${collection}/${docId}?key=${FIREBASE.apiKey}`, { method: "DELETE", headers });
    return res.ok;
  } catch { return false; }
}

async function fsCreate(collection, data) {
  try {
    const token = await getAuthToken();
    const hdrs = { "Content-Type": "application/json" };
    if (token) hdrs.Authorization = `Bearer ${token}`;
    const body = JSON.stringify({
      fields: {
        data: { stringValue: JSON.stringify(data) },
        updatedAt: { stringValue: new Date().toISOString() },
      },
    });
    const res = await fetch(`${FS_BASE}/${collection}?key=${FIREBASE.apiKey}`, {
      method: "POST",
      headers: hdrs,
      body,
    });
    if (!res.ok) {
      const errText = await res.text();
      console.error("fsCreate error:", res.status, errText);
      return null;
    }
    const doc = await res.json();
    return doc.name.split("/").pop();
  } catch (err) {
    console.error("fsCreate exception:", err);
    return null;
  }
}

// Track seed route codes to identify user additions
const SEED_ROUTE_SET = new Set();
// Will be populated after SEED_BLOCK_TABLE is defined

function isUserRoute(route) {
  return !SEED_ROUTE_SET.has(route.route + "|" + (route.aoc || "EST"));
}
function isUserAirport(ap) {
  return !ap.id?.match(/^a\d+$/);
}

