// Atlas Air (5Y) — US ACMI partner: tails beginning with "3" (e.g. 3-XXXX)
// MSC Air (CP) — Italian AOC: tails beginning with "I" (e.g. I-XXXX)
const AOC_DEFS_LIGHT = {
  ATLAS: { code: "5Y", name: "Atlas Air",  stripe: "#135193", bg: "#EBF0F7", text: "#1B365D" },
  MSC:   { code: "CP", name: "MSC Air",    stripe: "#325854", bg: "#EBF1F0", text: "#325854" },
  OTHER: { code: "??", name: "Other",      stripe: "#8B8178", bg: "#F3F1EE", text: "#222221" },
};
const AOC_DEFS_DARK = {
  ATLAS: { code: "5Y", name: "Atlas Air",  stripe: "#4A7AB5", bg: "#171D28", text: "#8BADD4" },
  MSC:   { code: "CP", name: "MSC Air",    stripe: "#4DA87A", bg: "#151F1A", text: "#6BC494" },
  OTHER: { code: "??", name: "Other",      stripe: "#6B6560", bg: "#1A1A1E", text: "#9A9490" },
};
const AOC_DEFS = new Proxy({}, { get(_, prop) { return (C === C_DARK ? AOC_DEFS_DARK : AOC_DEFS_LIGHT)[prop]; } });

function deriveAoc(reg) {
  const r = (reg || "").toUpperCase();
  if (r.startsWith("3")) return AOC_DEFS.ATLAS;
  if (r.startsWith("I")) return AOC_DEFS.MSC;
  return AOC_DEFS.OTHER;
}

