const REGION_MAP = {E:"Europe",A:"Asia",M:"MiddleEast",N:"NorthAmerica",S:"SouthAmerica",C:"Caribbean",F:"Africa",O:"Oceania"};
// ── Block time regression model (from aircraft performance data) ──────────
// Block time model: base linear + direction factor scaling with distance
// block = (slope × dist + intercept) × (1 + k_dir × dist/10000) × wind_correction
// Block time model v3: refitted on 1,982 points (451 OFP + 1,531 performance, OFP weighted 3×)
// Architecture: block = (slope × dist + intercept) × dir_factor × wind_factor
// Unified regression — intercept absorbs taxi + climb/descent overhead (~43m)
const BLOCK_MODEL = {
  W: { slope: 0.074998, intercept: 43.4, kEW: 0.0781, kWE: -0.0846, kNS: -0.0846, kSN: -0.0662, n: 992 },
  S: { slope: 0.073616, intercept: 43.9, kEW: 0.0542, kWE: -0.0547, kNS: -0.0771, kSN: -0.0676, n: 990 },
};
const DIR_KEYS = { "East\u2192West": "kEW", "West\u2192East": "kWE", "North\u2192South": "kNS", "South\u2192North": "kSN" };

// Block-time payload model — original single curve (legacy fallback)
// Fuel burn P75 quadratic: fuel = -0.077084 * block² + 199.15 * block - 13656
// Calibrated capacity: 186,000 kg (MTOW - OEW), structural max: 105,000 kg
const FUEL_MODEL = { a: -0.077084, b: 199.15, c: -13656, capacity: 186000, structMax: 105000, n: 4638 };

// AOC-specific fuel curves (2 AOC x 2 payload states)
// Converted from gallons to kg using 1 US gal Jet-A = 3.04 kg.
// Source: cost model analysis of 3,304 route simulations.
// fuel_kg = a × block² + b × block + c
// - "empty" = ferry/positioning flights (0 payload)
// - "loaded" = revenue flights (any cargo onboard)
const FUEL_MODELS = {
  CP: {
    empty:  { a:  0.023782, b:  68.86, c:    -52, n: 3304 },
    loaded: { a:  0.000404, b: 139.69, c: -4569,  n: 3304 },
  },
  "5Y": {
    empty:  { a:  0.023213, b:  71.35, c:     36, n: 3304 },
    loaded: { a: -0.023068, b: 160.76, c: -9004,  n: 3304 },
  },
  capacity: 186000,
  structMax: 105000,
};

/**
 * Estimate fuel burn in kg from block time. Uses AOC-specific loaded/empty curve
 * when available, falls back to legacy single model.
 * @param {number} blockMins - Block time in minutes
 * @param {string} [aoc] - Airline operator code ("CP" or "5Y")
 * @param {boolean} [isEmpty=false] - True for ferry/positioning (no cargo)
 */
function estimateFuelBurn(blockMins, aoc, isEmpty) {
  if (blockMins <= 0) return 0;
  const curve = (aoc && FUEL_MODELS[aoc]) ? FUEL_MODELS[aoc][isEmpty ? "empty" : "loaded"] : FUEL_MODEL;
  return Math.max(0, Math.round(curve.a * blockMins * blockMins + curve.b * blockMins + curve.c));
}

/**
 * Payload estimate from block time (minutes). Uses AOC-specific loaded curve
 * when available, falls back to legacy single model.
 * @param {number} blockMins - Block time in minutes
 * @param {string} [aoc] - Airline operator code ("CP" or "5Y")
 */
function estimatePayloadByBlock(blockMins, aoc) {
  if (blockMins <= 0) return FUEL_MODELS.structMax;
  const fuel = estimateFuelBurn(blockMins, aoc, false);
  return Math.min(FUEL_MODELS.structMax, Math.max(0, Math.round(FUEL_MODELS.capacity - fuel)));
}

// Airport regions are now inline in AIRPORT_DATA (r field)

// Seasonal wind corrections (22 winter + 23 summer region pairs)
// Fitted per-season from 1,982 combined data points with OFP weighting
const WIND_CORRECTION = {
  W: {
    "Africa\u2192Europe":1.032,"Asia\u2192Asia":1.060,"Asia\u2192Europe":1.042,"Asia\u2192MiddleEast":1.010,
    "Asia\u2192NorthAmerica":0.964,"Caribbean\u2192Europe":0.941,
    "Europe\u2192Asia":1.056,"Europe\u2192Europe":1.023,"Europe\u2192MiddleEast":0.966,
    "Europe\u2192NorthAmerica":0.950,"Europe\u2192SouthAmerica":0.876,
    "MiddleEast\u2192Asia":0.968,"MiddleEast\u2192Europe":1.000,
    "NorthAmerica\u2192Asia":0.952,"NorthAmerica\u2192Caribbean":1.058,
    "NorthAmerica\u2192Europe":0.941,"NorthAmerica\u2192NorthAmerica":0.941,
    "NorthAmerica\u2192SouthAmerica":0.925,"Oceania\u2192Asia":0.971,
    "SouthAmerica\u2192Europe":0.958,"SouthAmerica\u2192NorthAmerica":0.914,
    "SouthAmerica\u2192SouthAmerica":0.963,
  },
  S: {
    "Africa\u2192Europe":1.021,"Asia\u2192Asia":1.051,"Asia\u2192Europe":1.048,"Asia\u2192MiddleEast":0.966,
    "Asia\u2192NorthAmerica":0.973,"Caribbean\u2192Europe":0.947,
    "Europe\u2192Asia":1.038,"Europe\u2192Europe":1.032,"Europe\u2192MiddleEast":0.971,
    "Europe\u2192NorthAmerica":0.958,"Europe\u2192SouthAmerica":0.900,
    "MiddleEast\u2192Asia":1.002,"MiddleEast\u2192Europe":0.992,"MiddleEast\u2192MiddleEast":0.969,
    "NorthAmerica\u2192Asia":0.956,"NorthAmerica\u2192Caribbean":1.066,
    "NorthAmerica\u2192Europe":0.941,"NorthAmerica\u2192NorthAmerica":0.947,
    "NorthAmerica\u2192SouthAmerica":0.934,"Oceania\u2192Asia":0.993,
    "SouthAmerica\u2192Europe":0.958,"SouthAmerica\u2192NorthAmerica":0.930,
    "SouthAmerica\u2192SouthAmerica":0.987,
  },
};

/** Haversine great-circle distance in km */
function haversineGCD(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const toRad = d => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1), dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2)**2 + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

/** Detect flight direction from coordinates */
function detectDirection(lat1, lon1, lat2, lon2) {
  const dLon = lon2 - lon1;
  const dLat = lat2 - lat1;
  // Normalise longitude delta for date line
  const normDLon = ((dLon + 540) % 360) - 180;
  const absLon = Math.abs(normDLon), absLat = Math.abs(dLat);
  if (absLon > absLat * 0.7) {
    return normDLon > 0 ? "West→East" : "East→West";
  }
  return dLat > 0 ? "South→North" : "North→South";
}

/**
 * Estimate block time (mins), payload (kg), and fuel burn (kg) for a route.
 * @param {string} depCode - Departure IATA code
 * @param {string} arrCode - Arrival IATA code
 * @param {string} season - "W" or "S"
 * @param {string} [aoc] - Optional AOC for fuel/payload model selection
 */
function estimateBlock(depCode, arrCode, season, aoc) {
  const dep = AIRPORT_DATA[depCode], arr = AIRPORT_DATA[arrCode];
  if (!dep || !arr) return null;
  const dist = haversineGCD(dep.lat, dep.lon, arr.lat, arr.lon);
  const dir = detectDirection(dep.lat, dep.lon, arr.lat, arr.lon);
  const m = BLOCK_MODEL[season];
  if (!m) return null;

  // Base block estimate
  const base = m.slope * dist + m.intercept;

  // Direction factor (scales with distance)
  const dk = DIR_KEYS[dir];
  const dirFactor = 1 + (dk ? m[dk] : 0) * (dist / 10000);

  // Seasonal wind correction by region pair
  const depReg = (REGION_MAP[AIRPORT_DATA[depCode]?.r]) || "Other";
  const arrReg = (REGION_MAP[AIRPORT_DATA[arrCode]?.r]) || "Other";
  const regionPair = `${depReg}→${arrReg}`;
  const wc = WIND_CORRECTION[season] || {};
  const windFactor = wc[regionPair] || 1.0;

  const adjMins = base * dirFactor * windFactor;
  const blockRounded = Math.max(30, Math.round(adjMins / 5) * 5);
  const payloadKg = estimatePayloadByBlock(blockRounded, aoc);
  const fuelKg = estimateFuelBurn(blockRounded, aoc, false);
  return { dist: Math.round(dist), dir, blockMins: blockRounded, payloadKg, fuelKg, season,
           n: m.n, payloadN: FUEL_MODEL.n, windFactor, dirFactor: +dirFactor.toFixed(3),
           regionPair, depReg, arrReg };
}



