// ── ID counters (mutable — used for generating unique IDs) ───────────────────
let nextFlightId    = 184;
let nextBlockTimeId = 995;
let nextAirportId   = 10000;

function genFlightId()    { return "f"  + (nextFlightId++); }
function genBlockTimeId() { return "bt" + (nextBlockTimeId++); }
function genAirportId()   { return "a"  + (nextAirportId++); }

/** Normalize flight number: remove spaces between carrier code and number, uppercase, trim.
 *  e.g. "CP 192" → "CP192", " 5y 336 " → "5Y336" */
function normFlightNum(fn) {
  if (!fn) return "";
  return fn.toString().trim().toUpperCase().replace(/\s+/g, "").slice(0, 10);
}

/** Sanitise route: uppercase, trim, enforce XXX-YYY format, max 9 chars */
function sanitiseRoute(route) {
  if (!route) return "";
  const r = route.toString().trim().toUpperCase().replace(/[^A-Z0-9\-]/g, "");
  return r.slice(0, 9);
}

/** Sanitise free-text fields to prevent injection — strip HTML tags and limit length */
function sanitiseText(text, maxLen = 200) {
  if (!text) return "";
  return text.toString().replace(/<[^>]*>/g, "").trim().slice(0, maxLen);
}

function genAircraftId()  { return "ac" + Date.now(); }

/** Get the Monday date for a given ISO week number and year.
 *  ISO 8601: Week 1 is the week containing the first Thursday of the year. */
function isoWeekToDate(week, year) {
  // Jan 4 is always in week 1
  const jan4 = new Date(year, 0, 4);
  const dayOfWeek = jan4.getDay() || 7; // Mon=1..Sun=7
  const mon1 = new Date(jan4);
  mon1.setDate(jan4.getDate() - dayOfWeek + 1); // Monday of week 1
  const target = new Date(mon1);
  target.setDate(mon1.getDate() + (week - 1) * 7);
  return target;
}

/** Format a Date as "DD MMM" (e.g. "05 May") */
function fmtDDMMM(date) {
  if (!date || isNaN(date.getTime())) return "";
  const months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  return `${String(date.getDate()).padStart(2, "0")} ${months[date.getMonth()]}`;
}

/** Format a Date as "YYYY-MM-DD" */
function fmtISO(date) {
  if (!date || isNaN(date.getTime())) return "";
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}-${String(date.getDate()).padStart(2, "0")}`;
}

/** Format a Date as "DD-MM-YYYY" */
function fmtDDMMYYYY(date) {
  if (!date || isNaN(date.getTime())) return "";
  return `${String(date.getDate()).padStart(2, "0")}-${String(date.getMonth() + 1).padStart(2, "0")}-${date.getFullYear()}`;
}

/** Get the date for a specific day (1=Mon..7=Sun) in a given ISO week */
function weekDayDate(week, year, day) {
  if (!week || !year) return null;
  const mon = isoWeekToDate(week, year);
  const d = new Date(mon);
  d.setDate(mon.getDate() + (day - 1));
  return d;
}
function genMxBlockId()   { return "mx" + Date.now() + Math.random().toString(36).slice(2, 6); }

/** After loading a scenario, advance all ID counters past existing IDs to prevent collisions */
function bumpIdCounters(state) {
  const maxNum = (arr, prefix) => {
    let max = 0;
    for (const item of arr) {
      if (item.id && typeof item.id === "string" && item.id.startsWith(prefix)) {
        const n = parseInt(item.id.slice(prefix.length), 10);
        if (!isNaN(n) && n >= max) max = n + 1;
      }
    }
    return max;
  };
  if (state.flights)    nextFlightId    = Math.max(nextFlightId,    maxNum(state.flights,    "f"));
  if (state.blockTable) nextBlockTimeId = Math.max(nextBlockTimeId, maxNum(state.blockTable, "bt"));
  if (state.airports)   nextAirportId   = Math.max(nextAirportId,   maxNum(state.airports,   "a"));
}


// ╔═══════════════════════════════════════════════════════════════════════════╗
// ║  SECTION 2 — PURE HELPER FUNCTIONS                                       ║
// ╚═══════════════════════════════════════════════════════════════════════════╝
// Note: toHHMM, parseHHMM, localTime, dayShiftUtc, dayShiftLocal,
// localDayShift, shiftDOW, DAY_MINS, and WEEK_MINS are imported from
// ./utils/time.js at the top of this file.

function fmtBT(m) { if (m == null) return "—"; const h = Math.floor(m/60), mm = m%60; return h > 0 ? `${h}h${mm > 0 ? ` ${mm}m` : ""}` : `${mm}m`; }

/** Snap minutes to nearest SNAP interval */
function snapM(m) { return Math.round(m / SNAP) * SNAP; }

/** Convert (day 1–7, dep mins) → absolute week minutes from Mon 00:00 */
function weekMins(day, dep) { return (day - 1) * DAY_MINS + dep; }

/** Convert absolute week minutes → SVG x position */
function wMinsToX(wm) { return LABEL_WIDTH + (wm / 60) * HOUR_WIDTH; }

/** "HH:MM" string → minutes */
function minsFromHHMM(s) {
  if (s === null || s === undefined || s === "") return 0;
  // Excel may return time as a decimal fraction of day (e.g. 0.5138 = 12:20)
  const n = Number(s);
  if (!isNaN(n) && n >= 0 && n < 1) {
    return Math.round(n * DAY_MINS);
  }
  // Also handle if Excel returned a number > 1 (date+time serial)
  if (!isNaN(n) && n >= 1 && n < 2) {
    return Math.round((n - Math.floor(n)) * DAY_MINS);
  }
  const str = String(s).trim();
  if (!str.includes(":")) return 0;
  const [h, m] = str.split(":").map(Number);
  return (h || 0) * 60 + (m || 0);
}

/** Format turn gap: <60m → "45m", ≥60m → "2h30m" */
function fmtTurn(m) {
  if (m < 60) return `${m}m`;
  const h = Math.floor(m / 60);
  const rem = m % 60;
  return rem > 0 ? `${h}h${String(rem).padStart(2, "0")}m` : `${h}h`;
}

/** Format kg with thousands separator, e.g. 28000 → "28,000 Kg" */
function fmtKg(kg) {
  if (!kg && kg !== 0) return "—";
  return `${Number(kg).toLocaleString("en-US", { maximumFractionDigits: 0 })} Kg`;
}
function fmtNum(n, dec = 1) {
  if (n == null) return "—";
  return Number(n).toLocaleString("en-US", { minimumFractionDigits: dec, maximumFractionDigits: dec });
}

/** Format days-of-week array → "12.4.6." string */
function formatDOWStr(days) {
  return ALL_DAYS.map(d => days.includes(d) ? String(d) : ".").join("");
}

/** Minimum turnaround for violation detection (Gantt highlights, warnings)
 *  - 3h full cargo turn: offload + upload at same station
 *  - 2h partial cargo turn: offload-only or upload-only at station
 *  - 1.5h tech stop: no cargo handling */
function getMinTurnFromPair(arrivingFlight, departingFlight) {
  const aType = arrivingFlight?.type  || "F";
  const dType = departingFlight?.type || "F";

  const aNoCargo = aType === "P" || aType === "M";
  const dNoCargo = dType === "P" || dType === "M";

  const offloading = !aNoCargo && (arrivingFlight?.cargoOp === "offload" || arrivingFlight?.cargoOp === "both");
  const uplifting  = !dNoCargo && (departingFlight?.cargoOp === "upload"  || departingFlight?.cargoOp === "both");

  if (offloading && uplifting) return { mins: CARGO_FULL_TURN, label: "full cargo turn" };
  if (offloading || uplifting) return { mins: CARGO_PARTIAL_TURN, label: "partial cargo turn" };
  return { mins: MIN_TURN, label: "tech stop" };
}

/** IATA season from date string: Summer = last Sun of Mar → last Sat of Oct */
function deriveSeason(dateStr) {
  if (!dateStr) return "W";
  const d = new Date(dateStr + "T00:00:00");
  const yr = d.getFullYear();

  const lastSunMar = new Date(yr, 2, 31);
  while (lastSunMar.getDay() !== 0) lastSunMar.setDate(lastSunMar.getDate() - 1);

  const lastSatOct = new Date(yr, 9, 31);
  while (lastSatOct.getDay() !== 6) lastSatOct.setDate(lastSatOct.getDate() - 1);

  return (d >= lastSunMar && d <= lastSatOct) ? "S" : "W";
}

/** Return YYYY-MM-DD for the most recent Monday on or before today */
function thisMonday() {
  const d = new Date();
  const day = d.getDay();
  d.setDate(d.getDate() - (day === 0 ? 6 : day - 1));
  return d.toISOString().slice(0, 10);
}

/** Snap any date string to the Monday of that week */
function snapToMonday(dateStr) {
  if (!dateStr) return thisMonday();
  const d = new Date(dateStr + "T00:00:00");
  const day = d.getDay();
  d.setDate(d.getDate() - (day === 0 ? 6 : day - 1));
  return d.toISOString().slice(0, 10);
}

/** Format date string → "03 Mar 2026" */
function fmtDate(dateStr) {
  if (!dateStr) return "";
  const d = new Date(dateStr + "T00:00:00");
  return d.toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" });
}

/** SSIM date format: "03MAR26" */
function ssimFmtDate(dateStr) {
  if (!dateStr) return "       ";
  const d = new Date(dateStr + "T00:00:00");
  return String(d.getDate()).padStart(2, "0") + SSIM_MONTHS[d.getMonth()] + String(d.getFullYear()).slice(2);
}

/** SSIM UTC variation: "+0300" or "-0530" */
function ssimUtcVar(offset) {
  const sign = offset >= 0 ? "+" : "-";
  const abs = Math.abs(offset);
  const h = Math.floor(abs);
  const m = Math.round((abs - h) * 60);
  return sign + String(h).padStart(2, "0") + String(m).padStart(2, "0");
}

// ── Input validation helpers ─────────────────────────────────────────────────

/** Validate route format: "XXX-YYY" (3-letter IATA codes) */
function isValidRoute(route) {
  return /^[A-Z]{3}-[A-Z]{3}$/.test((route || "").toUpperCase());
}

/** Validate block time is within sane range */
function isValidBlock(block) {
  const n = parseInt(block);
  return !isNaN(n) && n >= 15 && n <= 900;
}

/** Validate flight number format (allows "CP 192", "5Y 101", "CP192", "5Y-101", etc.) */
function isValidFlightNum(fn) {
  if (!fn) return true; // optional
  return /^(CP|5Y)[\s\-]?\d{1,4}$/i.test(fn.trim());
}

/** Validate IATA designator (exactly 2 alphanumeric chars) */
function isValidDesignator(des) {
  return /^[A-Z0-9]{2}$/.test((des || "").toUpperCase());
}

// ── Block time resolution — single source of truth ──────────────────────────
// Priority chain (per Peter's specification):
// 1. Find entries for the target AOC. If none exist, fall back to other AOC.
// 2. Within the AOC set: flight-number-specific entry takes priority.
// 3. No flight number match → use the base (non-flightNum) entry.
// 4. From the resolved entry: ops override > perf block (season-dependent).
// 5. If nothing in table → return null (caller handles estimate fallback).

/**
 * Resolve the best matching route table entry.
 * Pure function — safe to call from reducers and hooks alike.
 */
function resolveBlockEntry(blockTable, route, aoc, flightNum) {
  const uc = (route || "").toUpperCase();
  const allMatches = blockTable.filter(bt => bt.route.toUpperCase() === uc);
  if (!allMatches.length) return null;

  // Step 1: prefer target AOC entries; fall back to other AOC if none
  const aocEntries = aoc ? allMatches.filter(bt => bt.aoc === aoc) : [];
  const pool = aocEntries.length > 0 ? aocEntries : allMatches;

  // Step 2: within the pool, check for flight-number-specific entry
  const fnNorm = (flightNum || "").toUpperCase().replace(/[\s\-]/g, "");
  const fnMatch = fnNorm
    ? pool.find(bt => bt.flightNum && bt.flightNum.toUpperCase().replace(/[\s\-]/g, "") === fnNorm)
    : null;
  if (fnMatch) return fnMatch;

  // Step 3: base entry (no flightNum) within the pool
  const base = pool.find(bt => !bt.flightNum);
  if (base) return base;

  // Step 4: any entry in the pool (edge case: all entries have flightNums)
  return pool[0] || null;
}

/**
 * Extract block time from a resolved entry, applying ops > perf priority.
 */
function extractBlock(entry, season) {
  if (!entry) return null;
  if (season === "W") return (entry.opW && entry.opW > 0) ? entry.opW : entry.W;
  return (entry.opS && entry.opS > 0) ? entry.opS : entry.S;
}

/**
 * Extract payload from a resolved entry (season-dependent).
 */
function extractPayload(entry, season) {
  if (!entry) return null;
  return season === "W" ? (entry.payloadW ?? null) : (entry.payloadS ?? null);
}

/**
 * Full block time resolution: table lookup with estimate fallback.
 * Returns { block, payload, fuelKg, source: "table"|"estimated" } or null.
 */
function resolveBlockTime(blockTable, route, aoc, season, flightNum) {
  const entry = resolveBlockEntry(blockTable, route, aoc, flightNum);
  if (entry) {
    const block = extractBlock(entry, season);
    const payload = extractPayload(entry, season);
    const fuelKg = block ? estimateFuelBurn(block, aoc, false) : 0;
    return block ? { block, payload: payload || 0, fuelKg, source: "table", entry } : null;
  }
  // Estimate fallback (pass aoc for AOC-specific fuel/payload curves)
  const [dep, arr] = (route || "").toUpperCase().split("-");
  if (dep && arr) {
    const est = estimateBlock(dep, arr, season, aoc);
    if (est) return { block: est.blockMins, payload: est.payloadKg, fuelKg: est.fuelKg, source: "estimated", estimate: est };
  }
  return null;
}

/** Clamp departure to valid range */
function clampDep(dep) {
  return Math.max(0, Math.min(DAY_MINS - 15, dep));
}


