// ── Action types ─────────────────────────────────────────────────────────────
const A = {
  // Flights
  SET_FLIGHTS:    "SET_FLIGHTS",
  ADD_FLIGHT:     "ADD_FLIGHT",
  UPDATE_FLIGHT:  "UPDATE_FLIGHT",
  DELETE_FLIGHT:  "DELETE_FLIGHT",
  BULK_SHIFT:     "BULK_SHIFT",
  BULK_COPY_DAY:  "BULK_COPY_DAY",
  BULK_CLEAR_DAY: "BULK_CLEAR_DAY",
  SWAP_AIRCRAFT:  "SWAP_AIRCRAFT",

  // Bulk selection operations
  BULK_RETIME:    "BULK_RETIME",
  BULK_REASSIGN:  "BULK_REASSIGN",
  BULK_DELETE:    "BULK_DELETE",

  // Rotations (commercial groupings)
  ADD_ROTATION:      "ADD_ROTATION",
  UPDATE_ROTATION:   "UPDATE_ROTATION",
  DELETE_ROTATION:   "DELETE_ROTATION",
  ASSIGN_ROTATION:   "ASSIGN_ROTATION",   // assign flight(s) to a rotation

  // Maintenance blocks (ground time, not positioning flights)
  ADD_MX_BLOCK:      "ADD_MX_BLOCK",
  UPDATE_MX_BLOCK:   "UPDATE_MX_BLOCK",
  DELETE_MX_BLOCK:   "DELETE_MX_BLOCK",

  // Aircraft
  SET_AIRCRAFT:      "SET_AIRCRAFT",
  ADD_AIRCRAFT:      "ADD_AIRCRAFT",
  UPDATE_AIRCRAFT:   "UPDATE_AIRCRAFT",
  REMOVE_AIRCRAFT:   "REMOVE_AIRCRAFT",

  // Block times
  SET_BLOCK_TABLE:    "SET_BLOCK_TABLE",
  ADD_BLOCK_TIME:     "ADD_BLOCK_TIME",
  UPDATE_BLOCK_TIME:  "UPDATE_BLOCK_TIME",
  DELETE_BLOCK_TIME:  "DELETE_BLOCK_TIME",

  // Airports
  SET_AIRPORTS:     "SET_AIRPORTS",
  ADD_AIRPORT:      "ADD_AIRPORT",
  UPDATE_AIRPORT:   "UPDATE_AIRPORT",
  DELETE_AIRPORT:   "DELETE_AIRPORT",

  // State management
  LOAD_STATE:       "LOAD_STATE",

  // Metadata
  SET_SCHEDULE_DATE:  "SET_SCHEDULE_DATE",
  SET_SEASON:          "SET_SEASON",
  SET_SCENARIO_NAME:  "SET_SCENARIO_NAME",
  SET_TAB:            "SET_TAB",

  // Scenario
  LOAD_SCENARIO:      "LOAD_SCENARIO",
  LOAD_FULL_SCENARIO: "LOAD_FULL_SCENARIO",
  RESET:              "RESET",

  // History
  UNDO:          "UNDO",
  REDO:          "REDO",
  HISTORY_PUSH:  "HISTORY_PUSH",
};

// ── Initial state ────────────────────────────────────────────────────────────
function buildInitialState() {
  return {
    flights:      SEED_FLIGHTS,
    aircraft:     SEED_AIRCRAFT,
    blockTable:   SEED_BLOCK_TABLE,
    airports:     SEED_AIRPORTS,
    rotations:    [],  // { id, name, customer, notes, locked }
    mxBlocks:     [],  // { id, acId, day, start, duration, label }
    scheduleDate: "2026-03-02",
    activeSeason: "S",
    scenarioName: "Working Schedule",
    tab:          "gantt",

    // Baseline (for Compare tab) — set when a scenario file is loaded
    baselineFlights:  null,
    baselineAircraft: [],
    baselineName:     null,
  };
}

// ── Reducer ──────────────────────────────────────────────────────────────────
function scheduleReducer(state, action) {
  switch (action.type) {

    // ── Flights ────────────────────────────────────────────────────────
    case A.SET_FLIGHTS:
      return { ...state, flights: action.flights };

    case A.ADD_FLIGHT: {
      const f = { ...action.flight, id: action.flight.id || genFlightId() };
      f.flightNum = normFlightNum(f.flightNum);
      if (f.route) f.route = sanitiseRoute(f.route);
      if (f.customer) f.customer = sanitiseText(f.customer);
      // Ferry and maintenance flights never carry cargo
      if (f.type === "P" || f.type === "M") f.cargoOp = "none";
      // Auto-populate block + payload using the unified lookup
      let newBlockTable = state.blockTable;
      if (f.route) {
        const ac = state.aircraft.find(a => a.id === f.acId);
        const aoc = ac ? deriveAoc(ac.reg).code : null;
        const season = state.activeSeason || "S";
        const resolved = resolveBlockTime(state.blockTable, f.route, aoc, season, f.flightNum);
        if (resolved) {
          if (!f.block) f.block = resolved.block;
          if (!f.payload) f.payload = resolved.payload;
          // Auto-add estimated routes to the route table (only if not already present)
          if (resolved.source === "estimated") {
            const routeUC = f.route.toUpperCase();
            const alreadyInTable = state.blockTable.some(bt => bt.route.toUpperCase() === routeUC && bt.aoc === (aoc || "5Y") && !bt.flightNum);
            if (!alreadyInTable) {
              const [dep, arr] = routeUC.split("-");
              const estW = estimateBlock(dep, arr, "W");
              const estS = estimateBlock(dep, arr, "S");
              newBlockTable = [...state.blockTable, {
                id: genBlockTimeId(), route: routeUC,
                W: estW?.blockMins || 0, S: estS?.blockMins || 0,
                payloadW: estW?.payloadKg || 0, payloadS: estS?.payloadKg || 0,
                opW: 0, opS: 0, aoc: aoc || "5Y", estimated: true,
              }];
            }
          }
        }
      }
      return { ...state, flights: [...state.flights, f], blockTable: newBlockTable };
    }

    case A.UPDATE_FLIGHT: {
      const updates = { ...action.flight };
      if (updates.flightNum !== undefined) updates.flightNum = normFlightNum(updates.flightNum);
      if (updates.route !== undefined) updates.route = sanitiseRoute(updates.route);
      if (updates.customer !== undefined) updates.customer = sanitiseText(updates.customer);
      // Ferry and maintenance flights never carry cargo — auto-enforce on type change
      if (updates.type === "P" || updates.type === "M") updates.cargoOp = "none";
      return {
        ...state,
        flights: state.flights.map(f =>
          f.id === updates.id ? { ...f, ...updates } : f
        ),
      };
    }

    case A.DELETE_FLIGHT:
      return {
        ...state,
        flights: state.flights.filter(f => f.id !== action.id),
      };

    case A.BULK_SHIFT: {
      const { acId, shiftMins, day: targetDay } = action;
      const mins = parseInt(shiftMins) || 0;
      if (!mins) return state;
      return {
        ...state,
        flights: state.flights.map(f => {
          if (f.acId !== acId) return f;
          if (targetDay !== 0 && f.day !== targetDay) return f;
          let newDep = f.dep + mins;
          let newDay = f.day;
          while (newDep >= DAY_MINS) { newDep -= DAY_MINS; newDay = Math.min(7, newDay + 1); }
          while (newDep < 0)         { newDep += DAY_MINS; newDay = Math.max(1, newDay - 1); }
          return { ...f, dep: newDep, day: newDay };
        }),
      };
    }

    case A.BULK_COPY_DAY: {
      const { acId, fromDay, toDay } = action;
      const src = state.flights.filter(f => f.acId === acId && f.day === fromDay);
      if (!src.length) return state;
      const filtered = state.flights.filter(f => !(f.acId === acId && f.day === toDay));
      const copies = src.map(f => ({ ...f, id: genFlightId(), day: toDay }));
      return { ...state, flights: [...filtered, ...copies] };
    }

    case A.BULK_CLEAR_DAY: {
      const { acId, day } = action;
      return {
        ...state,
        flights: state.flights.filter(f => !(f.acId === acId && f.day === day)),
      };
    }

    case A.SWAP_AIRCRAFT: {
      const { fromAcId, toAcId, day: targetDay } = action;
      if (fromAcId === toAcId) return state;
      return {
        ...state,
        flights: state.flights.map(f => {
          if (f.acId !== fromAcId) return f;
          if (targetDay && f.day !== targetDay) return f;
          return { ...f, acId: toAcId };
        }),
      };
    }

    // ── Bulk selection operations ─────────────────────────────────────
    case A.BULK_RETIME: {
      const { ids, shiftMins } = action;
      const idSet = ids instanceof Set ? ids : new Set(ids);
      return {
        ...state,
        flights: state.flights.map(f => {
          if (!idSet.has(f.id)) return f;
          let newDep = f.dep + shiftMins;
          // Handle day wrapping
          let newDay = f.day;
          while (newDep < 0) { newDep += DAY_MINS; newDay = newDay > 1 ? newDay - 1 : 7; }
          while (newDep >= DAY_MINS) { newDep -= DAY_MINS; newDay = newDay < 7 ? newDay + 1 : 1; }
          return { ...f, dep: newDep, day: newDay };
        }),
      };
    }

    case A.BULK_REASSIGN: {
      const { ids, toAcId } = action;
      const idSet = ids instanceof Set ? ids : new Set(ids);
      return {
        ...state,
        flights: state.flights.map(f => idSet.has(f.id) ? { ...f, acId: toAcId } : f),
      };
    }

    case A.BULK_DELETE: {
      const { ids } = action;
      const idSet = ids instanceof Set ? ids : new Set(ids);
      return {
        ...state,
        flights: state.flights.filter(f => !idSet.has(f.id)),
      };
    }

    // ── Rotations (commercial groupings) ──────────────────────────────
    case A.ADD_ROTATION: {
      const rot = { id: "rot_" + Date.now() + "_" + Math.random().toString(36).slice(2, 6), name: action.name || "New Rotation", customer: action.customer || "", notes: action.notes || "", locked: false };
      return { ...state, rotations: [...(state.rotations || []), rot] };
    }
    case A.UPDATE_ROTATION: {
      return { ...state, rotations: (state.rotations || []).map(r => r.id === action.id ? { ...r, ...action.updates } : r) };
    }
    case A.DELETE_ROTATION: {
      // Unassign flights that belong to this rotation
      return { ...state, rotations: (state.rotations || []).filter(r => r.id !== action.id), flights: state.flights.map(f => f.rotationId === action.id ? { ...f, rotationId: null } : f) };
    }
    case A.ASSIGN_ROTATION: {
      const idSet = new Set(action.flightIds);
      return { ...state, flights: state.flights.map(f => idSet.has(f.id) ? { ...f, rotationId: action.rotationId } : f) };
    }

    // ── Maintenance Blocks ────────────────────────────────────────────
    case A.ADD_MX_BLOCK: {
      const { acId, day, start, duration, label } = action;
      return {
        ...state,
        mxBlocks: [...(state.mxBlocks || []), {
          id: genMxBlockId(), acId, day: day || 1, start: start || 0,
          duration: duration || 900, label: label || "MX",
        }],
      };
    }
    case A.UPDATE_MX_BLOCK:
      return { ...state, mxBlocks: (state.mxBlocks || []).map(b => b.id === action.block.id ? { ...b, ...action.block } : b) };
    case A.DELETE_MX_BLOCK:
      return { ...state, mxBlocks: (state.mxBlocks || []).filter(b => b.id !== action.id) };

    // ── Aircraft ──────────────────────────────────────────────────────
    case A.SET_AIRCRAFT:
      return { ...state, aircraft: action.aircraft };

    case A.ADD_AIRCRAFT: {
      const reg = (action.reg || "").trim().toUpperCase();
      if (!reg) return state;
      return {
        ...state,
        aircraft: [...state.aircraft, {
          id: genAircraftId(),
          reg,
          maxPayload: action.maxPayload ?? 105000,
        }],
      };
    }

    case A.UPDATE_AIRCRAFT:
      return {
        ...state,
        aircraft: state.aircraft.map(a =>
          a.id === action.aircraft.id ? { ...a, ...action.aircraft } : a
        ),
      };

    case A.REMOVE_AIRCRAFT:
      return {
        ...state,
        aircraft: state.aircraft.filter(a => a.id !== action.id),
        flights:  state.flights.filter(f => f.acId !== action.id),
      };

    // ── Block times ───────────────────────────────────────────────────
    case A.SET_BLOCK_TABLE:
      return { ...state, blockTable: action.blockTable };

    case A.ADD_BLOCK_TIME: {
      const { route, W, S, payloadW, payloadS, estimated, aoc, opW, opS, flightNum } = action;
      if (!route.trim()) return state;
      const normRoute = route.trim().toUpperCase();
      const normAoc = aoc || "5Y";
      const normFn = (flightNum || "").trim().toUpperCase() || "";
      // Prevent duplicates: if route+AOC+flightNum already exists, update instead of adding
      const existing = state.blockTable.find(bt => bt.route.toUpperCase() === normRoute && bt.aoc === normAoc && (bt.flightNum || "") === normFn);
      if (existing) {
        return {
          ...state,
          blockTable: state.blockTable.map(bt =>
            bt.id === existing.id
              ? { ...bt, W: parseInt(W) || bt.W, S: parseInt(S) || bt.S, payloadW: parseInt(payloadW) || bt.payloadW, payloadS: parseInt(payloadS) || bt.payloadS, opW: parseInt(opW) || bt.opW, opS: parseInt(opS) || bt.opS, estimated: !!estimated && bt.estimated, aoc: normAoc, flightNum: normFn, modified: true }
              : bt
          ),
        };
      }
      return {
        ...state,
        blockTable: [
          ...state.blockTable,
          { id: genBlockTimeId(), route: normRoute, W: parseInt(W) || 90, S: parseInt(S) || 85, payloadW: parseInt(payloadW) || 0, payloadS: parseInt(payloadS) || 0, opW: parseInt(opW) || 0, opS: parseInt(opS) || 0, estimated: !!estimated, aoc: normAoc, flightNum: normFn, modified: !estimated },
        ],
      };
    }

    case A.UPDATE_BLOCK_TIME:
      return {
        ...state,
        blockTable: state.blockTable.map(r =>
          r.id === action.row.id ? { ...r, ...action.row, modified: true } : r
        ),
      };

    case A.DELETE_BLOCK_TIME:
      return {
        ...state,
        blockTable: state.blockTable.filter(r => r.id !== action.id),
      };

    // ── Airports ──────────────────────────────────────────────────────
    case A.SET_AIRPORTS:
      return { ...state, airports: action.airports };

    case A.ADD_AIRPORT: {
      const { code, name, utcOffset, utcOffsetS, lat, lon, depOpen, depClose, arrOpen, arrClose, notes } = action;
      if (!code.trim()) return state;
      return {
        ...state,
        airports: [
          ...state.airports,
          {
            id:          genAirportId(),
            code:        code.trim().toUpperCase(),
            name:        name || "",
            utcOffset:   parseFloat(utcOffset) || 0,
            utcOffsetS:  utcOffsetS != null ? parseFloat(utcOffsetS) : (parseFloat(utcOffset) || 0),
            lat:         lat ?? null,
            lon:         lon ?? null,
            depOpen:     depOpen  ?? null,
            depClose:    depClose ?? null,
            arrOpen:     arrOpen  ?? null,
            arrClose:    arrClose ?? null,
            notes:       notes || "",
          },
        ],
      };
    }

    case A.UPDATE_AIRPORT:
      return {
        ...state,
        airports: state.airports.map(a =>
          a.id === action.airport.id ? { ...a, ...action.airport, modified: true } : a
        ),
      };

    case A.DELETE_AIRPORT:
      return {
        ...state,
        airports: state.airports.filter(a => a.id !== action.id),
      };

    // ── Metadata ──────────────────────────────────────────────────────
    case A.SET_SCHEDULE_DATE:
      return { ...state, scheduleDate: action.date };
    case A.SET_SEASON: {
      const newSeason = action.season;
      const updatedFlights = state.flights.map(f => {
        const route = (f.route || "").toUpperCase();
        if (!route) return f;
        const ac = state.aircraft.find(a => a.id === f.acId);
        const aoc = ac ? deriveAoc(ac.reg).code : null;
        const resolved = resolveBlockTime(state.blockTable, route, aoc, newSeason, f.flightNum);
        if (resolved) return { ...f, block: resolved.block, payload: resolved.payload };
        return f;
      });
      return { ...state, activeSeason: newSeason, flights: updatedFlights };
    }

    case A.SET_SCENARIO_NAME:
      return { ...state, scenarioName: action.name };

    case A.SET_TAB:
      return { ...state, tab: action.tab };

    // ── Scenario load / reset ─────────────────────────────────────────
    case A.LOAD_SCENARIO: {
      const { aircraft, scenarioName, baselineName } = action;
      const flights = (action.flights || []).map(f => ({ ...f, flightNum: normFlightNum(f.flightNum) }));
      bumpIdCounters({ flights });
      return {
        ...state,
        flights,
        aircraft,
        mxBlocks:         [],  // Excel imports don't contain MX blocks — clear them
        scenarioName:     scenarioName || state.scenarioName,
        baselineFlights:  flights,
        baselineAircraft: aircraft,
        baselineName:     baselineName || null,
        tab:              "gantt",
      };
    }

    case A.LOAD_FULL_SCENARIO: {
      // JSON restore — replaces everything
      const d = { ...action.data };
      if (d.flights) d.flights = d.flights.map(f => ({ ...f, flightNum: normFlightNum(f.flightNum) }));
      bumpIdCounters({ flights: d.flights, blockTable: d.blockTable, airports: d.airports });

      // Merge saved blockTable onto seed data: saved entries override seed by route+aoc+flightNum
      let mergedBlockTable = state.blockTable;
      if (d.blockTable && d.blockTable.length > 0) {
        const savedMap = new Map();
        d.blockTable.forEach(r => {
          const key = (r.route || "").toUpperCase() + "|" + (r.aoc || "") + "|" + (r.flightNum || "");
          savedMap.set(key, r);
        });
        // Start with seed, override with saved entries
        mergedBlockTable = SEED_BLOCK_TABLE.map(seed => {
          const key = (seed.route || "").toUpperCase() + "|" + (seed.aoc || "") + "|" + (seed.flightNum || "");
          const saved = savedMap.get(key);
          if (saved) { savedMap.delete(key); return { ...seed, ...saved }; }
          return seed;
        });
        // Append any saved entries that don't exist in seed (user-added routes, flight overrides)
        savedMap.forEach(r => mergedBlockTable.push(r));
      }

      // Merge saved airports onto seed data
      let mergedAirports = state.airports;
      if (d.airports && d.airports.length > 0) {
        const savedApMap = new Map();
        d.airports.forEach(a => savedApMap.set((a.code || "").toUpperCase(), a));
        mergedAirports = SEED_AIRPORTS.map(seed => {
          const saved = savedApMap.get((seed.code || "").toUpperCase());
          if (saved) {
            savedApMap.delete((seed.code || "").toUpperCase());
            // Preserve seed restrictionType/cargoExempt if saved data doesn't have them
            return { ...seed, ...saved, restrictionType: saved.restrictionType ?? seed.restrictionType, cargoExempt: saved.cargoExempt ?? seed.cargoExempt };
          }
          return seed;
        });
        savedApMap.forEach(a => mergedAirports.push(a));
      }

      return {
        ...state,
        flights:          d.flights        || state.flights,
        aircraft:         d.aircraft       || state.aircraft,
        blockTable:       mergedBlockTable,
        airports:         mergedAirports,
        rotations:        d.rotations      || state.rotations || [],
        mxBlocks:         d.mxBlocks       || [],
        scheduleDate:     d.scheduleDate   || state.scheduleDate,
        activeSeason:     d.activeSeason   || state.activeSeason,
        scenarioName:     d.scenarioName   || state.scenarioName,
        baselineFlights:  d.flights        || state.flights,
        baselineAircraft: d.aircraft       || state.aircraft,
        baselineName:     d.scenarioName   || "Loaded JSON",
        tab:              "gantt",
      };
    }

    case A.RESET:
      return {
        ...buildInitialState(),
        blockTable:   state.blockTable,
        airports:     state.airports,
        scheduleDate: state.scheduleDate,
        activeSeason: state.activeSeason,
      };

    // ── State management ─────────────────────────────────────────────
    case A.LOAD_STATE:
      if (action.state) bumpIdCounters(action.state);
      return {
        ...buildInitialState(),
        ...action.state,
        tab: state.tab,
      };

    default:
      return state;
  }
}

// ── Context ──────────────────────────────────────────────────────────────────

// Actions that don't push onto the undo stack (UI-only / non-destructive)
const SKIP_HISTORY = new Set([A.SET_TAB, A.SET_SCENARIO_NAME, A.SET_SCHEDULE_DATE, A.UNDO, A.REDO]);
const MAX_HISTORY = 80;

/**
 * Wraps scheduleReducer with an undo/redo history stack.
 *
 * Shape: { present, past: [...], future: [...] }
 *
 * - UNDO  → move present to future, pop past into present
 * - REDO  → move present to past, pop future into present
 * - Skip-history actions or actions with _noHistory flag → mutate present only
 * - All other actions → snapshot present to past, clear future
 */
function historyReducer(history, action) {
  const { past, present, future } = history;

  if (action.type === A.UNDO) {
    if (!past.length) return history;
    return {
      past:    past.slice(0, -1),
      present: past[past.length - 1],
      future:  [present, ...future].slice(0, MAX_HISTORY),
    };
  }

  if (action.type === A.REDO) {
    if (!future.length) return history;
    return {
      past:    [...past, present].slice(-MAX_HISTORY),
      present: future[0],
      future:  future.slice(1),
    };
  }

  // Explicit snapshot — push current present to past without changing it
  // Used before drag/resize begins so undo returns to pre-drag state
  if (action.type === A.HISTORY_PUSH) {
    return {
      past:    [...past, present].slice(-MAX_HISTORY),
      present,
      future:  [],
    };
  }

  const next = scheduleReducer(present, action);
  if (next === present) return history; // no change

  // Skip history for transient updates (e.g. drag-in-progress) or UI-only actions
  if (SKIP_HISTORY.has(action.type) || action._noHistory) {
    return { past, present: next, future };
  }

  return {
    past:    [...past, present].slice(-MAX_HISTORY),
    present: next,
    future:  [], // new mutation clears redo stack
  };
}
const ScheduleContext = createContext(null);
const UIContext = createContext(null);
function useUI() { return useContext(UIContext); }

function ScheduleProvider({ children }) {
  const [history, dispatch] = useReducer(historyReducer, null, () => ({
    past: [],
    present: buildInitialState(),
    future: [],
  }));

  const state = history.present;
  const canUndo = history.past.length > 0;
  const canRedo = history.future.length > 0;

  // ── Keyboard shortcuts (Ctrl+Z / Ctrl+Shift+Z) ────────────────────
  useEffect(() => {
    function onKey(e) {
      const isMeta = e.metaKey || e.ctrlKey;
      if (!isMeta || e.key.toLowerCase() !== "z") return;
      e.preventDefault();
      dispatch({ type: e.shiftKey ? A.REDO : A.UNDO });
    }
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  // ── Firebase sync: shared route table + airports ─────────────────
  const [syncStatus, setSyncStatus] = useState("loading"); // loading | synced | saving | error | offline
  const syncTimer = useRef(null);
  const initialLoadDone = useRef(false);

  // Load shared data on mount
  useEffect(() => {
    let cancelled = false;
    async function loadShared() {
      setSyncStatus("loading");
      try {
        const [cloudRoutes, cloudAirports] = await Promise.all([
          fsGet("config", "routeTable"),
          fsGet("config", "airports"),
        ]);
        if (cancelled) return;
        if (cloudRoutes?.length) {
          // Merge cloud routes into current table (cloud overrides seed for matching route+aoc+flightNum)
          const merged = [...state.blockTable];
          cloudRoutes.forEach(cr => {
            const crFn = (cr.flightNum || "").trim().toUpperCase();
            const idx = merged.findIndex(r =>
              r.route === cr.route &&
              (r.aoc || "5Y") === (cr.aoc || "5Y") &&
              ((r.flightNum || "").trim().toUpperCase()) === crFn
            );
            if (idx >= 0) {
              merged[idx] = { ...merged[idx], ...cr, modified: true };
            } else {
              merged.push({ ...cr, modified: true });
            }
          });
          dispatch({ type: A.SET_BLOCK_TABLE, blockTable: merged, _noHistory: true });
        }
        if (cloudAirports?.length) {
          const merged = [...state.airports];
          cloudAirports.forEach(ca => {
            const idx = merged.findIndex(a => (a.code || "").toUpperCase() === (ca.code || "").toUpperCase());
            if (idx >= 0) {
              // Preserve seed restrictionType/cargoExempt if cloud data doesn't have them
              const seed = merged[idx];
              merged[idx] = {
                ...seed, ...ca, modified: true,
                restrictionType: ca.restrictionType ?? seed.restrictionType,
                cargoExempt: ca.cargoExempt ?? seed.cargoExempt,
              };
            } else {
              merged.push({ ...ca, modified: true });
            }
          });
          dispatch({ type: A.SET_AIRPORTS, airports: merged, _noHistory: true });
        }
        setSyncStatus("synced");
      } catch (e) {
        console.warn("Firestore load error:", e);
        setSyncStatus("offline");
      }
      initialLoadDone.current = true;
    }
    loadShared();
    return () => { cancelled = true; };
  }, []);

  // Debounced save when route table changes — only sync user-added/modified routes
  useEffect(() => {
    if (!initialLoadDone.current) return;
    if (syncTimer.current) clearTimeout(syncTimer.current);
    syncTimer.current = setTimeout(async () => {
      const userRoutes = state.blockTable.filter(r => isUserRoute(r) || r.estimated === false || r.modified);
      if (userRoutes.length === 0) { setSyncStatus(s => s === "offline" ? "offline" : "synced"); return; }
      setSyncStatus(s => s === "offline" ? "offline" : "saving");
      const ok = await fsSet("config", "routeTable", userRoutes);
      setSyncStatus(prev => !ok && prev === "offline" ? "offline" : ok ? "synced" : "error");
    }, 1500);
    return () => clearTimeout(syncTimer.current);
  }, [state.blockTable]);

  // Debounced save when airports change — only sync user-added/modified airports
  const airportTimer = useRef(null);
  useEffect(() => {
    if (!initialLoadDone.current) return;
    if (airportTimer.current) clearTimeout(airportTimer.current);
    airportTimer.current = setTimeout(async () => {
      const userAirports = state.airports.filter(a => isUserAirport(a) || a.modified);
      if (userAirports.length === 0) { setSyncStatus(s => s === "offline" ? "offline" : "synced"); return; }
      setSyncStatus(s => s === "offline" ? "offline" : "saving");
      const ok = await fsSet("config", "airports", userAirports);
      setSyncStatus(prev => !ok && prev === "offline" ? "offline" : ok ? "synced" : "error");
    }, 1500);
    return () => clearTimeout(airportTimer.current);
  }, [state.airports]);

  // ── Derived values (memoised) ──────────────────────────────────────
  const activeSeason = state.activeSeason || "W";

  const lookupBlock = useCallback((route, aoc, flightNum) => {
    const entry = resolveBlockEntry(state.blockTable, route, aoc, flightNum);
    return extractBlock(entry, activeSeason);
  }, [state.blockTable, activeSeason]);

  const lookupPayload = useCallback((route, aoc, flightNum) => {
    const entry = resolveBlockEntry(state.blockTable, route, aoc, flightNum);
    return extractPayload(entry, activeSeason);
  }, [state.blockTable, activeSeason]);

  const lookupBlockEntry = useCallback((route, aoc, flightNum) => {
    return resolveBlockEntry(state.blockTable, route, aoc, flightNum);
  }, [state.blockTable]);

  /** Get AOC code for a flight (based on its aircraft reg) */
  const flightAoc = useCallback((acId) => {
    const ac = state.aircraft.find(a => a.id === acId);
    return ac ? deriveAoc(ac.reg).code : null;
  }, [state.aircraft]);

  const lookupAirport = useCallback((code) => {
    const uc = (code || "").toUpperCase();
    const ap = state.airports.find(a => a.code.toUpperCase() === uc);
    if (ap) {
      const seasonalOffset = activeSeason === "S" ? (ap.utcOffsetS ?? ap.utcOffset) : ap.utcOffset;
      return { ...ap, utcOffset: seasonalOffset };
    }
    // Fall back to AIRPORT_DATA for airports not in user table
    const ad = AIRPORT_DATA[uc];
    if (!ad) return undefined;
    const w = ad.w ?? 0, s = ad.s ?? ad.w ?? 0;
    return { code: uc, name: uc, utcOffset: activeSeason === "S" ? s : w, utcOffsetS: s, lat: ad.lat, lon: ad.lon, depOpen: null, depClose: null, arrOpen: null, arrClose: null, restrictionType: undefined, notes: "" };
  }, [state.airports, activeSeason]);

  // SVG dimensions (depend on aircraft count)
  const svgWidth  = LABEL_WIDTH + (WEEK_MINS / 60) * HOUR_WIDTH;
  const svgHeight = HEADER_H + (state.aircraft.length + 2) * ROW_HEIGHT + 24;

  const ctx = useMemo(() => ({
    ...state,
    dispatch,
    activeSeason,
    lookupBlock,
    lookupPayload,
    lookupBlockEntry,
    flightAoc,
    lookupAirport,
    svgWidth,
    svgHeight,
    canUndo,
    canRedo,
    syncStatus,
  }), [state, activeSeason, lookupBlock, lookupPayload, lookupBlockEntry, flightAoc, lookupAirport, svgWidth, svgHeight, canUndo, canRedo, syncStatus]);

  return (
    <ScheduleContext.Provider value={ctx}>
      {children}
    </ScheduleContext.Provider>
  );
}

/** Hook to consume schedule context — throws if used outside provider */
function useSchedule() {
  const ctx = useContext(ScheduleContext);
  if (!ctx) throw new Error("useSchedule must be used within <ScheduleProvider>");
  return ctx;
}

// ── Auto-diff summary generator ──────────────────────────────────────────────
function generateChangeSummary(baseFlt, baseAc, verFlt, verAc) {
  function pKey(f) { return `${f.route}|${f.dep}|${f.block}|${f.type}`; }
  function buildMap(fList) {
    const m = {};
    (fList || []).forEach(f => {
      const k = pKey(f);
      if (!m[k]) m[k] = { route: f.route, dep: f.dep, block: f.block, type: f.type, days: [] };
      m[k].days.push(f.day || 1);
    });
    return m;
  }
  const bm = buildMap(baseFlt), vm = buildMap(verFlt);
  const allK = new Set([...Object.keys(bm), ...Object.keys(vm)]);
  const added = [], removed = [], changed = [];
  allK.forEach(k => {
    const b = bm[k], v = vm[k];
    if (b && !v) removed.push(b);
    else if (!b && v) added.push(v);
    else if (b && v) {
      const bd = [...b.days].sort().join(","), vd = [...v.days].sort().join(",");
      if (b.dep !== v.dep || b.block !== v.block || bd !== vd) changed.push({ from: b, to: v });
    }
  });

  // Build title fragments
  const parts = [];
  if (added.length) {
    const routes = [...new Set(added.map(a => a.route))];
    const show = routes.slice(0, 2).join(", ");
    parts.push(`+${added.length} ${routes.length <= 2 ? show : show + " +" + (routes.length - 2)}`);
  }
  if (removed.length) {
    const routes = [...new Set(removed.map(r => r.route))];
    const show = routes.slice(0, 2).join(", ");
    parts.push(`−${removed.length} ${routes.length <= 2 ? show : show + " +" + (routes.length - 2)}`);
  }
  if (changed.length) parts.push(`~${changed.length} retimed`);
  const title = parts.length ? parts.join(", ") : "No changes";

  // Build detail lines
  const details = [];
  added.forEach(a => details.push(`Added ${a.route} (${a.type}) DOW ${a.days.sort().join("")}`));
  removed.forEach(r => details.push(`Removed ${r.route} (${r.type}) DOW ${r.days.sort().join("")}`));
  changed.forEach(c => {
    const dd = c.to.dep - c.from.dep;
    const db = c.to.block - c.from.block;
    const p = [];
    if (dd) p.push(`dep ${dd > 0 ? "+" : ""}${dd}m`);
    if (db) p.push(`blk ${db > 0 ? "+" : ""}${db}m`);
    const fd = [...c.from.days].sort().join(""), td = [...c.to.days].sort().join("");
    if (fd !== td) p.push(`DOW ${fd}→${td}`);
    details.push(`Changed ${c.from.route}: ${p.join(", ")}`);
  });

  return {
    title,
    summary: details.join("\n"),
    counts: { added: added.length, removed: removed.length, changed: changed.length },
  };
}

// ── Version repository hook (persistent storage) ─────────────────────────────
const MONTH_NAMES_FULL = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];

// ═══════════════════════════════════════════════════════════════════════
// CLOUD SCENARIO MANAGER — Firebase-backed scenario library + snapshots
// ═══════════════════════════════════════════════════════════════════════

function useCloudScenarios() {
  const [scenarios, setScenarios] = useState([]);
  const [activeId, setActiveId]   = useState(null);
  const [loading, setLoading]     = useState(true);
  const [saving, setSaving]       = useState(false);

  const refresh = useCallback(async () => {
    const docs = await fsList("scenarios");
    const parsed = docs.map(d => ({
      id: d.id,
      updatedAt: d.updatedAt,
      name: d.data?.name || "Untitled",
      season: d.data?.season || "S",
      flightCount: d.data?.flights?.length || 0,
      aircraftCount: d.data?.aircraft?.length || 0,
      snapshotCount: d.data?.snapshots?.length || 0,
      isBaseline: !!d.data?.isBaseline,
      notes: d.data?.notes || "",
      month: d.data?.month || "",
      author: d.data?.author || "",
      weekNum: d.data?.weekNum || null,
      weekYear: d.data?.weekYear || null,
    })).sort((a, b) => (b.updatedAt || "").localeCompare(a.updatedAt || ""));
    setScenarios(parsed);
    setLoading(false);
    return parsed;
  }, []);

  useEffect(() => { refresh(); }, [refresh]);

  const saveScenario = useCallback(async (id, state, meta) => {
    setSaving(true);
    const payload = {
      name: state.scenarioName || "Untitled",
      season: state.activeSeason || "S",
      flights: (state.flights || []).map(f => ({
        id: f.id, acId: f.acId, route: f.route, dep: f.dep, block: f.block,
        type: f.type, flightNum: f.flightNum, day: f.day,
        cargoOp: f.cargoOp, payload: f.payload, customer: f.customer || "", rotationId: f.rotationId || null, curfewWaiver: f.curfewWaiver || false,
      })),
      aircraft: (state.aircraft || []).map(a => ({
        id: a.id, reg: a.reg, maxPayload: a.maxPayload,
      })),
      scheduleDate: state.scheduleDate,
      activeSeason: state.activeSeason,
      rotations: state.rotations || [],
      mxBlocks: (state.mxBlocks || []).map(mx => ({
        id: mx.id, acId: mx.acId, day: mx.day, start: mx.start,
        duration: mx.duration, label: mx.label || "",
      })),
      blockTable: (state.blockTable || []).filter(r => isUserRoute(r) || r.estimated === false || r.modified).map(r => ({
        id: r.id, route: r.route, aoc: r.aoc || "5Y", W: r.W, S: r.S,
        opW: r.opW || 0, opS: r.opS || 0, payloadW: r.payloadW || 0, payloadS: r.payloadS || 0,
        flightNum: r.flightNum || "", estimated: !!r.estimated, modified: !!r.modified,
      })),
      airports: (state.airports || []).filter(a => isUserAirport(a) || a.modified).map(a => ({
        id: a.id, code: a.code, name: a.name, utcOffset: a.utcOffset, utcOffsetS: a.utcOffsetS,
        lat: a.lat, lon: a.lon, depOpen: a.depOpen, depClose: a.depClose,
        arrOpen: a.arrOpen, arrClose: a.arrClose, cargoExempt: a.cargoExempt || false,
        restrictionType: a.restrictionType || "none", notes: a.notes || "", modified: !!a.modified,
      })),
    };
    // Preserve/update metadata
    try {
      const existing = await fsGet("scenarios", id);
      if (existing?.isBaseline) payload.isBaseline = true;
      // Preserve existing metadata, allow override via meta param
      payload.notes    = meta?.notes    ?? existing?.notes    ?? "";
      payload.month    = meta?.month    ?? existing?.month    ?? "";
      payload.author   = meta?.author   ?? existing?.author   ?? "";
      payload.weekNum  = meta?.weekNum  ?? existing?.weekNum  ?? null;
      payload.weekYear = meta?.weekYear ?? existing?.weekYear ?? null;
      payload.acknowledgedIssues = meta?.acknowledgedIssues ?? existing?.acknowledgedIssues ?? [];
    } catch {
      payload.notes    = meta?.notes    ?? "";
      payload.month    = meta?.month    ?? "";
      payload.author   = meta?.author   ?? "";
      payload.weekNum  = meta?.weekNum  ?? null;
      payload.weekYear = meta?.weekYear ?? null;
      payload.acknowledgedIssues = meta?.acknowledgedIssues ?? [];
    }
    await fsSet("scenarios", id, payload);
    setSaving(false);
    return true;
  }, []);

  const createScenario = useCallback(async (state, name, meta = {}) => {
    setSaving(true);
    const payload = {
      name: name || state.scenarioName || "New Scenario",
      season: state.activeSeason || "S",
      notes: meta.notes || "",
      month: meta.month || "",
      author: meta.author || "",
      weekNum: meta.weekNum ?? null,
      weekYear: meta.weekYear ?? null,
      acknowledgedIssues: meta.acknowledgedIssues || [],
      flights: (state.flights || []).map(f => ({
        id: f.id, acId: f.acId, route: f.route, dep: f.dep, block: f.block,
        type: f.type, flightNum: f.flightNum, day: f.day,
        cargoOp: f.cargoOp, payload: f.payload, customer: f.customer || "", rotationId: f.rotationId || null, curfewWaiver: f.curfewWaiver || false,
      })),
      aircraft: (state.aircraft || []).map(a => ({
        id: a.id, reg: a.reg, maxPayload: a.maxPayload,
      })),
      scheduleDate: state.scheduleDate,
      activeSeason: state.activeSeason,
      rotations: state.rotations || [],
      mxBlocks: (state.mxBlocks || []).map(mx => ({
        id: mx.id, acId: mx.acId, day: mx.day, start: mx.start,
        duration: mx.duration, label: mx.label || "",
      })),
      blockTable: (state.blockTable || []).filter(r => isUserRoute(r) || r.estimated === false || r.modified).map(r => ({
        id: r.id, route: r.route, aoc: r.aoc || "5Y", W: r.W, S: r.S,
        opW: r.opW || 0, opS: r.opS || 0, payloadW: r.payloadW || 0, payloadS: r.payloadS || 0,
        flightNum: r.flightNum || "", estimated: !!r.estimated, modified: !!r.modified,
      })),
      airports: (state.airports || []).filter(a => isUserAirport(a) || a.modified).map(a => ({
        id: a.id, code: a.code, name: a.name, utcOffset: a.utcOffset, utcOffsetS: a.utcOffsetS,
        lat: a.lat, lon: a.lon, depOpen: a.depOpen, depClose: a.depClose,
        arrOpen: a.arrOpen, arrClose: a.arrClose, cargoExempt: a.cargoExempt || false,
        restrictionType: a.restrictionType || "none", notes: a.notes || "", modified: !!a.modified,
      })),
    };
    try {
      const newId = await fsCreate("scenarios", payload);
      setSaving(false);
      if (newId) {
        setActiveId(newId);
        await refresh();
      }
      return newId;
    } catch (err) {
      setSaving(false);
      console.error("createScenario failed:", err);
      return null;
    }
  }, [refresh]);

  const loadScenario = useCallback(async (id) => {
    const data = await fsGet("scenarios", id);
    if (data) setActiveId(id);
    return data;
  }, []);

  const deleteScenario = useCallback(async (id) => {
    await fsDelete("scenarios", id);
    // Also delete snapshots
    const snaps = await fsList(`scenarios/${id}/snapshots`);
    for (const s of snaps) {
      await fsDelete(`scenarios/${id}/snapshots`, s.id);
    }
    if (activeId === id) setActiveId(null);
    await refresh();
  }, [activeId, refresh]);

  const renameScenario = useCallback(async (id, newName) => {
    const data = await fsGet("scenarios", id);
    if (!data) return false;
    data.name = newName;
    await fsSet("scenarios", id, data);
    await refresh();
    return true;
  }, [refresh]);

  // Snapshot management
  const saveSnapshot = useCallback(async (scenarioId, state, title) => {
    const payload = {
      title: title || `Snapshot ${new Date().toLocaleString("en-GB", { day: "2-digit", month: "short", hour: "2-digit", minute: "2-digit" })}`,
      savedAt: new Date().toISOString(),
      flights: (state.flights || []).map(f => ({
        id: f.id, acId: f.acId, route: f.route, dep: f.dep, block: f.block,
        type: f.type, flightNum: f.flightNum, day: f.day,
        cargoOp: f.cargoOp, payload: f.payload, customer: f.customer || "", rotationId: f.rotationId || null, curfewWaiver: f.curfewWaiver || false,
      })),
      aircraft: (state.aircraft || []).map(a => ({
        id: a.id, reg: a.reg, maxPayload: a.maxPayload,
      })),
      activeSeason: state.activeSeason,
      scenarioName: state.scenarioName,
    };
    return await fsCreate(`scenarios/${scenarioId}/snapshots`, payload);
  }, []);

  const listSnapshots = useCallback(async (scenarioId) => {
    const docs = await fsList(`scenarios/${scenarioId}/snapshots`);
    return docs.map(d => ({
      id: d.id,
      title: d.data?.title || "Snapshot",
      savedAt: d.data?.savedAt || d.updatedAt,
      flightCount: d.data?.flights?.length || 0,
    })).sort((a, b) => (b.savedAt || "").localeCompare(a.savedAt || ""));
  }, []);

  const loadSnapshot = useCallback(async (scenarioId, snapId) => {
    return await fsGet(`scenarios/${scenarioId}/snapshots`, snapId);
  }, []);

  const deleteSnapshot = useCallback(async (scenarioId, snapId) => {
    return await fsDelete(`scenarios/${scenarioId}/snapshots`, snapId);
  }, []);

  const [defaultId, setDefaultIdState] = useState(null);

  // Load default scenario ID on mount
  useEffect(() => {
    (async () => {
      const cfg = await fsGet("config", "defaultScenario");
      if (cfg?.id) setDefaultIdState(cfg.id);
    })();
  }, []);

  const setDefaultScenario = useCallback(async (id) => {
    const ok = await fsSet("config", "defaultScenario", { id });
    if (ok) setDefaultIdState(id);
    return ok;
  }, []);

  const clearDefaultScenario = useCallback(async () => {
    const ok = await fsSet("config", "defaultScenario", { id: null });
    if (ok) setDefaultIdState(null);
    return ok;
  }, []);

  return {
    scenarios, activeId, setActiveId, loading, saving,
    refresh, saveScenario, createScenario, loadScenario,
    deleteScenario, renameScenario,
    saveSnapshot, listSnapshots, loadSnapshot, deleteSnapshot,
    defaultId, setDefaultScenario, clearDefaultScenario,
  };
}

function useVersionRepo() {
  const [baselines, setBaselines] = useState([]);
  const [versions, setVersions]   = useState([]);
  const [loading, setLoading]     = useState(true);

  const refresh = useCallback(async () => {
    try {
      const [bRes, vRes] = await Promise.all([
        window.storage.list("base:"),
        window.storage.list("ver:"),
      ]);
      const bItems = [], vItems = [];
      for (const k of (bRes?.keys || [])) {
        try { const r = await window.storage.get(k); if (r) bItems.push({ key: k, ...JSON.parse(r.value) }); } catch (_) {}
      }
      for (const k of (vRes?.keys || [])) {
        try { const r = await window.storage.get(k); if (r) vItems.push({ key: k, ...JSON.parse(r.value) }); } catch (_) {}
      }
      bItems.sort((a, b) => (b.month || "").localeCompare(a.month || ""));
      vItems.sort((a, b) => (b.savedAt || "").localeCompare(a.savedAt || ""));
      setBaselines(bItems);
      setVersions(vItems);
    } catch (_) { setBaselines([]); setVersions([]); }
    setLoading(false);
  }, []);

  useEffect(() => { refresh(); }, [refresh]);

  const saveBaseline = useCallback(async (month, data) => {
    const key = `base:${month}`;
    const payload = {
      month,
      name: `${MONTH_NAMES_FULL[parseInt(month.split("-")[1]) - 1]} ${month.split("-")[0]} Baseline`,
      savedAt: new Date().toISOString(),
      ...data,
    };
    try {
      await window.storage.set(key, JSON.stringify(payload));
      await refresh();
      return true;
    } catch (_) { return false; }
  }, [refresh]);

  const saveVersion = useCallback(async (month, title, summary, rationale, data) => {
    const key = `ver:${month}:${Date.now()}`;
    const payload = {
      month, title, summary, rationale,
      savedAt: new Date().toISOString(),
      ...data,
    };
    try {
      await window.storage.set(key, JSON.stringify(payload));
      await refresh();
      return true;
    } catch (_) { return false; }
  }, [refresh]);

  const deleteEntry = useCallback(async (key) => {
    try { await window.storage.delete(key); await refresh(); return true; } catch (_) { return false; }
  }, [refresh]);

  const updateEntry = useCallback(async (key, updates) => {
    try {
      const r = await window.storage.get(key);
      if (!r) return false;
      const data = { ...JSON.parse(r.value), ...updates };
      await window.storage.set(key, JSON.stringify(data));
      await refresh();
      return true;
    } catch (_) { return false; }
  }, [refresh]);

  const loadEntry = useCallback(async (key) => {
    try { const r = await window.storage.get(key); return r ? JSON.parse(r.value) : null; } catch (_) { return null; }
  }, []);

  const monthGroups = useMemo(() => {
    const months = new Set([
      ...baselines.map(b => b.month),
      ...versions.map(v => v.month),
    ]);
    return [...months].sort().reverse().map(m => ({
      month: m,
      label: `${MONTH_NAMES_FULL[parseInt(m.split("-")[1]) - 1]} ${m.split("-")[0]}`,
      baseline: baselines.find(b => b.month === m) || null,
      versions: versions.filter(v => v.month === m),
    }));
  }, [baselines, versions]);

  return { baselines, versions, monthGroups, loading, refresh, saveBaseline, saveVersion, deleteEntry, updateEntry, loadEntry };
}


// ╔═══════════════════════════════════════════════════════════════════════════╗
// ║  SECTION 4 — VALIDATION HOOK                                             ║
// ╚═══════════════════════════════════════════════════════════════════════════╝

/**
 * useScheduleValidation
 *
 * Provides every schedule-integrity check the app needs. Consumed by:
 *  - GanttTab (block colouring, turnaround indicators, tooltip warnings)
 *  - Edit / Add flight modals (inline validation feedback)
 *  - ScheduleTableTab (row-level warnings column, future)
 *
 * All functions are memoised with useCallback so they can be passed as
 * props or called inside other useCallback / useMemo chains without
 * triggering unnecessary re-renders.
 */
function useScheduleValidation() {
  const { flights, aircraft, lookupBlock, lookupBlockEntry, lookupAirport, flightAoc, activeSeason } = useSchedule();

  // ── Core checks ────────────────────────────────────────────────────

  /**
   * Curfew violations for a single flight.
   * Returns string[] — one entry per violated window.
   * Checks departure (origin) against depOpen/depClose and arrival (destination) against arrOpen/arrClose.
   */
  /**
   * Curfew violations and buffer warnings for a single flight.
   * Returns { errors: string[], warnings: string[] }
   *
   * Enhancements:
   * - Cargo-exempt airports: cargo flights (F, H) skip curfew checks
   * - Near-curfew buffer: WARN when within CURFEW_BUFFER_MINS of boundary
   * - Per-flight waiver: flight.curfewWaiver bypasses all checks (INFO returned by caller)
   */
  const curfewViolations = useCallback((flight) => {
    const errors = [], warnings = [];

    // Per-flight curfew waiver — skip all checks
    if (flight.curfewWaiver) return { errors, warnings };

    const [orig, dest] = (flight.route || "").split("-");
    const isCargo = flight.type === "F" || flight.type === "H";

    const checkWindow = (ap, utcMins, open, close, label) => {
      if (open == null || close == null) return;
      // Cargo-exempt airports skip curfew for cargo flights
      if (ap.cargoExempt && isCargo) return;

      const lt = localTime(utcMins, ap.utcOffset);
      const rType = ap.restrictionType || "hard_curfew"; // default to hard_curfew if window is set but no type
      const outside = open <= close
        ? (lt < open || lt > close)
        : (lt < open && lt > close);

      if (outside) {
        // Severity depends on restriction type
        if (rType === "hard_curfew") {
          errors.push(`${label} ${ap.code} ${toHHMM(lt)} local — ops ${toHHMM(open)}–${toHHMM(close)}`);
        } else if (rType === "quota") {
          warnings.push(`${label} ${ap.code} ${toHHMM(lt)} local — night quota system (ops ${toHHMM(open)}–${toHHMM(close)}). Verify slot availability with airport coordinator.`);
        } else if (rType === "prior_approval") {
          warnings.push(`${label} ${ap.code} ${toHHMM(lt)} local — prior approval required for night ops (ops ${toHHMM(open)}–${toHHMM(close)})`);
        } else if (rType === "temporary") {
          warnings.push(`${label} ${ap.code} ${toHHMM(lt)} local — temporary restriction active (ops ${toHHMM(open)}–${toHHMM(close)}). Check current NOTAM status.`);
        } else if (rType === "noise_managed") {
          warnings.push(`${label} ${ap.code} ${toHHMM(lt)} local — noise-managed airport, preferential procedures at night (ops ${toHHMM(open)}–${toHHMM(close)})`);
        } else {
          errors.push(`${label} ${ap.code} ${toHHMM(lt)} local — ops ${toHHMM(open)}–${toHHMM(close)}`);
        }
        return;
      }
      // Near-curfew buffer warning (inside window but close to boundary)
      if (CURFEW_BUFFER_MINS > 0 && (rType === "hard_curfew" || rType === "quota")) {
        const distToOpen = open <= close
          ? (lt - open + DAY_MINS) % DAY_MINS
          : (lt >= open ? lt - open : lt + DAY_MINS - open);
        const distToClose = open <= close
          ? (close - lt + DAY_MINS) % DAY_MINS
          : (lt <= close ? close - lt : close + DAY_MINS - lt);
        if (distToOpen < CURFEW_BUFFER_MINS) {
          warnings.push(`${label} ${ap.code} ${toHHMM(lt)} local — within ${distToOpen}m of curfew open ${toHHMM(open)} (ops ${toHHMM(open)}–${toHHMM(close)})`);
        } else if (distToClose < CURFEW_BUFFER_MINS) {
          warnings.push(`${label} ${ap.code} ${toHHMM(lt)} local — within ${distToClose}m of curfew close ${toHHMM(close)} (ops ${toHHMM(open)}–${toHHMM(close)})`);
        }
      }
    };

    const origAp = lookupAirport(orig);
    const destAp = lookupAirport(dest);
    if (origAp) checkWindow(origAp, flight.dep, origAp.depOpen, origAp.depClose, "DEP");
    if (destAp) checkWindow(destAp, flight.dep + flight.block, destAp.arrOpen, destAp.arrClose, "ARR");
    return { errors, warnings };
  }, [lookupAirport, activeSeason]);

  /**
   * Schedule conflict: does this flight's time block overlap another
   * flight on the same aircraft and same day-of-week?
   */
  const hasConflict = useCallback((f) => {
    const fStart = weekMins(f.day, f.dep);
    const fEnd   = fStart + f.block;
    return flights.some(o =>
      o.id !== f.id &&
      o.acId === f.acId &&
      (() => {
        const oStart = weekMins(o.day, o.dep);
        const oEnd   = oStart + o.block;
        return oStart < fEnd && fStart < oEnd;
      })()
    );
  }, [flights]);

  /**
   * Station connectivity: does this flight's origin match the previous
   * flight's destination, and does this flight's destination match the
   * next flight's origin — for the same aircraft across the full week?
   */
  const hasConnectivityIssue = useCallback((f) => {
    const acFlights = [...flights.filter(x => x.acId === f.acId)]
      .sort((a, b) => weekMins(a.day, a.dep) - weekMins(b.day, b.dep));
    const idx = acFlights.findIndex(x => x.id === f.id);
    if (idx === -1) return false;

    const [orig, dest] = (f.route || "").split("-");

    // Check forward: my dest must match next flight's orig
    if (idx < acFlights.length - 1) {
      const nextOrig = (acFlights[idx + 1].route || "").split("-")[0];
      if (dest && nextOrig && dest !== nextOrig) return true;
    }
    // Check backward: prev flight's dest must match my orig
    if (idx > 0) {
      const prevDest = (acFlights[idx - 1].route || "").split("-")[1];
      if (prevDest && orig && prevDest !== orig) return true;
    }
    return false;
  }, [flights]);

  /**
   * Does the flight's block time differ from ALL known block-time values
   * for this route? Only flags if it matches neither performance nor operational.
   */
  const hasBlockMismatch = useCallback((flight) => {
    const aoc = flightAoc(flight.acId);
    const entry = lookupBlockEntry(flight.route, aoc, flight.flightNum);
    if (!entry) return false;
    // Use the same priority chain: ops > perf
    const correctBlock = extractBlock(entry, activeSeason);
    if (!correctBlock || correctBlock <= 0) return false;
    return flight.block !== correctBlock;
  }, [lookupBlockEntry, flightAoc, activeSeason]);

  // ── Turnaround analysis ────────────────────────────────────────────

  /**
   * Compute turnaround gaps between consecutive flights for one
   * aircraft on one day. Returns an array of gap objects with
   * SVG-ready positioning data for Gantt rendering.
   *
   * Each gap object:
   *   { gapMins, x1, x2, cx, gapPx, minTurn, isViolation,
   *     arrivingFlight, departingFlight }
   */
  const getTurnaroundsForDay = useCallback((acId, day) => {
    const sorted = [...flights
      .filter(f => f.acId === acId && f.day === day)]
      .sort((a, b) => a.dep - b.dep);

    const gaps = [];
    for (let i = 0; i < sorted.length - 1; i++) {
      const curr = sorted[i];
      const next = sorted[i + 1];
      const arrMins = curr.dep + curr.block;
      const gap = next.dep - arrMins;

      // gap >= 0: normal turnaround (including zero = instant turn, always a violation)
      // gap < 0: overlap / conflict
      const turn = getMinTurnFromPair(curr, next);
      const isViolation = gap < turn.mins;
      const isOverlap = gap < 0;
      const dayOffset = (day - 1) * DAY_MINS;

      gaps.push({
        gapMins:          gap,
        arrWMins:         dayOffset + arrMins,
        depWMins:         dayOffset + next.dep,
        minTurn:          turn.mins,
        turnLabel:        isOverlap ? "overlap" : turn.label,
        isViolation,
        isOverlap,
        arrivingFlight:   curr,
        departingFlight:  next,
      });
    }
    return gaps;
  }, [flights]);

  /**
   * Compute turnaround gaps between ALL consecutive flights for one
   * aircraft across the entire week. This connects blocks across day
   * boundaries (e.g. last flight Monday → first flight Tuesday).
   */
  const getAllTurnarounds = useCallback((acId) => {
    const sorted = [...flights
      .filter(f => f.acId === acId)]
      .sort((a, b) => weekMins(a.day, a.dep) - weekMins(b.day, b.dep));

    const gaps = [];
    for (let i = 0; i < sorted.length - 1; i++) {
      const curr = sorted[i];
      const next = sorted[i + 1];
      const arrWM = weekMins(curr.day, curr.dep) + curr.block;
      const depWM = weekMins(next.day, next.dep);
      const gap = depWM - arrWM;

      const turn = getMinTurnFromPair(curr, next);
      const isViolation = gap < turn.mins;
      const isOverlap = gap < 0;

      gaps.push({
        gapMins:          gap,
        arrWMins:         arrWM,
        depWMins:         depWM,
        minTurn:          turn.mins,
        turnLabel:        isOverlap ? "overlap" : turn.label,
        isViolation,
        isOverlap,
        arrivingFlight:   curr,
        departingFlight:  next,
      });
    }

    // Week wrap-around: last flight (Sunday end) → first flight (Monday start)
    if (sorted.length >= 2) {
      const last = sorted[sorted.length - 1];
      const first = sorted[0];
      const lastArrWM = weekMins(last.day, last.dep) + last.block;
      // Only if the last flight's block extends past or near the week end
      if (lastArrWM > WEEK_MINS - DAY_MINS) { // last flight is on Sunday or overflows into it
        const firstDepWM = weekMins(first.day, first.dep);
        const gap = (firstDepWM + WEEK_MINS) - lastArrWM;
        const turn = getMinTurnFromPair(last, first);
        const isViolation = gap < turn.mins;
        const isOverlap = gap < 0;
        gaps.push({
          gapMins:          gap,
          arrWMins:         lastArrWM,
          depWMins:         firstDepWM,
          minTurn:          turn.mins,
          turnLabel:        isOverlap ? "overlap" : turn.label,
          isViolation,
          isOverlap,
          arrivingFlight:   last,
          departingFlight:  first,
          isWeekWrap:       true,
        });
      }
    }

    return gaps;
  }, [flights]);

  // ── Comprehensive flight validation ────────────────────────────────

  /**
   * Validate a flight object and return an array of error strings.
   * Used by Add / Edit flight modals to show inline feedback.
   *
   * Returns { errors: string[], warnings: string[] }
   *  - errors   = hard blocks (should prevent save)
   *  - warnings = informational (allow save but flag)
   */
  const validateFlight = useCallback((flight) => {
    const errors = [];
    const warnings = [];

    // Route format
    if (!flight.route || !flight.route.trim()) {
      errors.push("Route is required");
    } else if (!isValidRoute(flight.route)) {
      errors.push("Route must be XXX-YYY (3-letter IATA codes)");
    } else {
      // Check origin ≠ destination
      const [orig, dest] = flight.route.split("-");
      if (orig === dest) {
        errors.push("Origin and destination cannot be the same");
      }
    }

    // Block time
    if (!flight.block || flight.block < 15) {
      errors.push("Block time must be at least 15 minutes");
    } else if (flight.block > 900) {
      errors.push("Block time cannot exceed 900 minutes (15 hours)");
    }

    // Departure
    if (flight.dep == null || flight.dep < 0) {
      errors.push("Departure time is required");
    } else if (flight.dep >= DAY_MINS) {
      errors.push("Departure must be within 00:00–23:59");
    }

    // Day
    if (!flight.day || flight.day < 1 || flight.day > 7) {
      errors.push("Day of week must be 1 (Mon) – 7 (Sun)");
    }

    // Flight number (optional but validated if present)
    if (flight.flightNum && !isValidFlightNum(flight.flightNum)) {
      warnings.push("Flight number format looks unusual (expected e.g. CP 192 or 5Y 101)");
    }

    // Block mismatch warning
    const tb = lookupBlock(flight.route, flightAoc(flight.acId), flight.flightNum);
    if (tb !== null && flight.block !== tb) {
      warnings.push(`Block time (${flight.block}m) differs from table (${tb}m)`);
    }

    // Curfew warning
    if (flight.route && flight.dep != null && flight.block) {
      const cv = curfewViolations(flight);
      cv.errors.forEach(v => warnings.push(`Curfew: ${v}`));
      cv.warnings.forEach(v => warnings.push(`Curfew buffer: ${v}`));
    }

    // Payload vs max structural
    if (flight.payload > 0 && flight.acId) {
      const ac = aircraft.find(a => a.id === flight.acId);
      if (ac?.maxPayload && flight.payload > ac.maxPayload) {
        warnings.push(`Payload (${fmtKg(flight.payload)}) exceeds max structural (${fmtKg(ac.maxPayload)})`);
      }
    }

    return { errors, warnings };
  }, [lookupBlock, curfewViolations, aircraft]);

  /**
   * Quick boolean: does this flight have any hard errors?
   */
  const hasErrors = useCallback((flight) => {
    return validateFlight(flight).errors.length > 0;
  }, [validateFlight]);

  /**
   * Aggregate all warnings for a flight (conflict, connectivity,
   * curfew, block mismatch) — used for tooltip display.
   */
  const getFlightWarnings = useCallback((flight) => {
    const w = [];
    if (hasConflict(flight))          w.push("Schedule conflict with another flight");
    if (hasConnectivityIssue(flight)) w.push("Station mismatch with adjacent flight");
    if (hasBlockMismatch(flight))     w.push(`Block time differs from table`);
    const cv = curfewViolations(flight);
    cv.errors.forEach(v => w.push(`Curfew: ${v}`));
    cv.warnings.forEach(v => w.push(`Curfew buffer: ${v}`));
    return w;
  }, [hasConflict, hasConnectivityIssue, hasBlockMismatch, curfewViolations]);

  return {
    // Core checks
    curfewViolations,
    hasConflict,
    hasConnectivityIssue,
    hasBlockMismatch,

    // Turnarounds
    getTurnaroundsForDay,
    getAllTurnarounds,

    // Comprehensive validation
    validateFlight,
    hasErrors,
    getFlightWarnings,
  };
}


// ╔═══════════════════════════════════════════════════════════════════════════╗
// ║  SECTION 4b — DRAG-AND-DROP HOOK                                         ║
// ╚═══════════════════════════════════════════════════════════════════════════╝

/**
 * useGanttDragDrop
 *
 * Encapsulates all drag (move) and resize behaviour for the Gantt chart.
 * Handles both mouse and touch events so the Gantt works on tablets.
 *
 * Architecture:
 *  - Two refs (dragRef, resizeRef) track the in-progress operation.
 *    Using refs instead of state avoids triggering re-renders on every
 *    mousemove — only the flight position state updates cause renders.
 *  - A single pair of move/end handlers is registered on `window` so
 *    the gesture continues even if the pointer leaves the SVG.
 *  - Row reassignment (dragging a block to a different aircraft row)
 *    is computed from the pointer's Y position relative to the SVG.
 *
 * Usage:
 *   const { startDrag, startResize, dragTarget, isDragging, isResizing }
 *     = useGanttDragDrop(svgRef);
 *
 * Parameters:
 *   svgRef — React ref to the Gantt <svg> element (for Y-position math)
 *
 * Returns:
 *   startDrag(event, flightId)    — call from onMouseDown / onTouchStart on the block rect
 *   startResize(event, flightId)  — call from onMouseDown / onTouchStart on the resize handle
 *   dragTarget                    — index of the aircraft row the pointer is hovering (or null)
 *   isDragging                    — true while a drag-move is active
 *   isResizing                    — true while a resize is active
 */
function useGanttDragDrop(svgRef, hourW, rowLayoutRef, displayAcRef, dragActiveRef, selectedRef) {
  const { flights, aircraft, dispatch } = useSchedule();

  const hourWRef = useRef(hourW);
  useEffect(() => { hourWRef.current = hourW; }, [hourW]);
  const flightsRef = useRef(flights);
  useEffect(() => { flightsRef.current = flights; }, [flights]);
  const aircraftRef = useRef(aircraft);
  useEffect(() => { aircraftRef.current = displayAcRef?.current || aircraft; }, [aircraft, displayAcRef?.current]);
  const dispatchRef = useRef(dispatch);
  useEffect(() => { dispatchRef.current = dispatch; }, [dispatch]);

  const dragRef   = useRef(null);
  const resizeRef = useRef(null);
  const dragEngagedRef = useRef(false);

  function clientXY(e) {
    if (e.touches && e.touches.length > 0) return { cx: e.touches[0].clientX, cy: e.touches[0].clientY };
    return { cx: e.clientX, cy: e.clientY };
  }

  const DRAG_THRESHOLD = 3;

  // ── Start drag — NO React state changes (no re-render) ───────────
  const startDrag = useCallback((e, flightId) => {
    e.preventDefault();
    e.stopPropagation();
    if (dragRef.current || resizeRef.current) return; // prevent double-start

    const f = flightsRef.current.find(x => x.id === flightId);
    if (!f) return;

    const { cx, cy } = clientXY(e);
    const origRowIdx = aircraftRef.current.findIndex(a => a.id === f.acId);

    dragEngagedRef.current = false;

    // Multi-select: if dragged flight is in selection and multiple are selected, capture group
    const sel = selectedRef?.current;
    const isMulti = sel && sel.size > 1 && sel.has(flightId);
    let groupFlights = null;
    if (isMulti) {
      const anchorWM = weekMins(f.day || 1, f.dep);
      groupFlights = flightsRef.current
        .filter(x => sel.has(x.id) && x.id !== flightId)
        .map(x => ({
          id: x.id,
          offsetWM: weekMins(x.day || 1, x.dep) - anchorWM,
          origDay: x.day || 1,
          origDep: x.dep,
        }));
    }

    // Capture original row Y for vertical visual offset during drag
    const origRowY = rowLayoutRef?.current?.ys?.[origRowIdx]?.y ?? 0;

    dragRef.current = {
      id:           flightId,
      startX:       cx,
      startCY:      cy,
      origWeekMins: weekMins(f.day || 1, f.dep),
      origAcId:     f.acId,
      targetRowIdx: origRowIdx,
      origRowIdx,
      origRowY,
      finalDay:     f.day || 1,
      finalDep:     f.dep,
      origBlock:    f.block,
      groupFlights, // null for single drag, array for multi
    };
  }, []);

  // ── Start resize ──────────────────────────────────────────────────
  const startResize = useCallback((e, flightId) => {
    e.preventDefault();
    e.stopPropagation();
    if (dragRef.current || resizeRef.current) return;

    const f = flightsRef.current.find(x => x.id === flightId);
    if (!f) return;

    const { cx } = clientXY(e);
    dragEngagedRef.current = false;

    resizeRef.current = {
      id:         flightId,
      startX:     cx,
      origBlock:  f.block,
      finalBlock: f.block,
    };
  }, []);

  // ── Pointer handlers — direct DOM manipulation, ZERO React dispatches during move ──
  useEffect(() => {
    function onPointerMove(e) {
      // ── Drag: move <g data-flight-id> via SVG transform ────────
      if (dragRef.current) {
        const drag = dragRef.current;
        const { cx, cy } = clientXY(e);

        if (!dragEngagedRef.current) {
          const totalDist = Math.sqrt((cx - drag.startX) ** 2 + (cy - (drag.startCY || cy)) ** 2);
          if (totalDist < DRAG_THRESHOLD) return;
          dragEngagedRef.current = true;
        }

        const dx = cx - drag.startX;
        const shiftHeld = e.shiftKey;

        // Compute snapped horizontal position
        // Shift key = lock time (only move between rows)
        let snappedDx = 0;
        if (!shiftHeld) {
          const deltaMin = (dx / hourWRef.current) * 60;
          let newWM = snapM(drag.origWeekMins + deltaMin);
          if (newWM < 0) newWM += WEEK_MINS;
          if (newWM >= WEEK_MINS) newWM -= WEEK_MINS;
          drag.finalDay = Math.floor(newWM / DAY_MINS) + 1;
          drag.finalDep = Math.round(newWM % DAY_MINS);
          // Snap visual translation to the grid position (account for week wrap)
          let actualDeltaMin = newWM - drag.origWeekMins;
          if (actualDeltaMin > WEEK_MINS / 2) actualDeltaMin -= WEEK_MINS;
          if (actualDeltaMin < -WEEK_MINS / 2) actualDeltaMin += WEEK_MINS;
          snappedDx = (actualDeltaMin / 60) * hourWRef.current;
        }

        // Compute vertical offset to target row + track target for mouseup
        let snappedDy = 0;
        if (svgRef.current && rowLayoutRef?.current) {
          const rect = svgRef.current.getBoundingClientRect();
          const svgY = cy - rect.top + (svgRef.current.parentElement?.scrollTop || 0);
          if (svgY >= HEADER_H) {
            const { ys } = rowLayoutRef.current;
            let rowIdx = ys.length - 1;
            for (let r = 0; r < ys.length; r++) {
              if (svgY < ys[r].y + ys[r].h) { rowIdx = r; break; }
            }
            drag.targetRowIdx = Math.max(0, Math.min(aircraftRef.current.length - 1, rowIdx));
            const targetRowY = ys[rowIdx]?.y ?? drag.origRowY;
            snappedDy = targetRowY - drag.origRowY;
          }
        }

        // Move the SVG group — NO state dispatch
        const el = svgRef.current?.querySelector(`[data-flight-id="${drag.id}"]`);
        if (el) {
          el.setAttribute("transform", `translate(${snappedDx},${snappedDy})`);
          el.style.opacity = "0.7";
        }

        // Multi-select: move group flights with the same visual offset
        if (drag.groupFlights) {
          for (const gf of drag.groupFlights) {
            const gEl = svgRef.current?.querySelector(`[data-flight-id="${gf.id}"]`);
            if (gEl) {
              gEl.setAttribute("transform", `translate(${snappedDx},${snappedDy})`);
              gEl.style.opacity = "0.7";
            }
          }
        }

        // Show live label during drag
        const timeLabel = svgRef.current?.querySelector(`[data-drag-label="${drag.id}"]`);
        if (!timeLabel && el && svgRef.current) {
          const ns = "http://www.w3.org/2000/svg";
          const lbl = document.createElementNS(ns, "text");
          lbl.setAttribute("data-drag-label", drag.id);
          lbl.setAttribute("font-size", "10");
          lbl.setAttribute("font-family", "Archivo, Arial, sans-serif");
          lbl.setAttribute("font-weight", "700");
          lbl.setAttribute("fill", "#1B365D");
          lbl.setAttribute("text-anchor", "middle");
          lbl.style.pointerEvents = "none";
          lbl.style.userSelect = "none";
          const bg = document.createElementNS(ns, "rect");
          bg.setAttribute("data-drag-label-bg", drag.id);
          bg.setAttribute("rx", "3");
          bg.setAttribute("fill", "#FFF8E1");
          bg.setAttribute("stroke", "#C5A43E");
          bg.setAttribute("stroke-width", "1");
          bg.style.pointerEvents = "none";
          svgRef.current.appendChild(bg);
          svgRef.current.appendChild(lbl);
        }
        const activeLbl = svgRef.current?.querySelector(`[data-drag-label="${drag.id}"]`);
        const activeBg = svgRef.current?.querySelector(`[data-drag-label-bg="${drag.id}"]`);
        if (activeLbl) {
          const h = Math.floor(drag.finalDep / 60);
          const m = drag.finalDep % 60;
          const dayNames = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];
          const dayStr = dayNames[(drag.finalDay - 1) % 7] || "";
          const depStr = `${String(h).padStart(2,"0")}:${String(m).padStart(2,"0")}`;
          const arrTotal = drag.finalDep + (drag.origBlock || 0);
          const arrDayOffset = Math.floor(arrTotal / DAY_MINS);
          const arrMin = arrTotal % DAY_MINS;
          const arrH = Math.floor(arrMin / 60);
          const arrM = arrMin % 60;
          const arrStr = `${String(arrH).padStart(2,"0")}:${String(arrM).padStart(2,"0")}`;
          const arrDayIdx = ((drag.finalDay - 1) + arrDayOffset) % 7;
          const arrDayStr = dayNames[arrDayIdx] || "";
          const showArrDay = arrDayOffset > 0 ? ` ${arrDayStr}` : "";
          const targetAcName = aircraftRef.current[drag.targetRowIdx]?.reg || "";
          activeLbl.textContent = shiftHeld
            ? `↕ ${targetAcName || "Move to row"}`
            : `${dayStr} ${depStr} → ${arrStr}${showArrDay}`;
          // Position above the block
          const origX = LABEL_WIDTH + (drag.origWeekMins / 60) * hourWRef.current;
          const blockW = ((drag.origBlock || 60) / 60) * hourWRef.current;
          const lblX = origX + snappedDx + blockW / 2;
          const elRect = el?.getBBox?.();
          const lblY = (elRect?.y || 0) - 6;
          activeLbl.setAttribute("x", String(lblX));
          activeLbl.setAttribute("y", String(lblY));
          if (activeBg) {
            const tw = activeLbl.textContent.length * 6.5;
            activeBg.setAttribute("x", String(lblX - tw / 2 - 4));
            activeBg.setAttribute("y", String(lblY - 10));
            activeBg.setAttribute("width", String(tw + 8));
            activeBg.setAttribute("height", "14");
          }
        }

        // (target row tracking is handled above in the vertical offset computation)
      }

      // ── Resize: store in ref, dispatch on mouseup ──────────────
      if (resizeRef.current) {
        const resize = resizeRef.current;
        const { cx } = clientXY(e);
        if (!dragEngagedRef.current) {
          if (Math.abs(cx - resize.startX) < DRAG_THRESHOLD) return;
          dragEngagedRef.current = true;
        }
        const deltaMin = ((cx - resize.startX) / hourWRef.current) * 60;
        resize.finalBlock = snapM(Math.max(15, Math.min(900, resize.origBlock + deltaMin)));
      }
    }

    function onPointerUp() {
      // ── Finalise drag: single dispatch ─────────────────────────
      if (dragRef.current) {
        const drag = dragRef.current;
        const el = svgRef.current?.querySelector(`[data-flight-id="${drag.id}"]`);
        if (el) { el.removeAttribute("transform"); el.style.opacity = ""; }
        // Remove the live time label and its background
        const lbl = svgRef.current?.querySelector(`[data-drag-label="${drag.id}"]`);
        if (lbl) lbl.remove();
        const lblBg = svgRef.current?.querySelector(`[data-drag-label-bg="${drag.id}"]`);
        if (lblBg) lblBg.remove();

        // Clean up group flight transforms
        if (drag.groupFlights) {
          for (const gf of drag.groupFlights) {
            const gEl = svgRef.current?.querySelector(`[data-flight-id="${gf.id}"]`);
            if (gEl) { gEl.removeAttribute("transform"); gEl.style.opacity = ""; }
          }
        }

        if (dragEngagedRef.current) {
          dispatchRef.current({ type: A.HISTORY_PUSH });
          // Update anchor flight
          const updates = { id: drag.id, day: drag.finalDay, dep: drag.finalDep };
          const targetAc = aircraftRef.current[drag.targetRowIdx];
          if (targetAc) updates.acId = targetAc.id;
          dispatchRef.current({ type: A.UPDATE_FLIGHT, flight: updates, _noHistory: true });

          // Update group flights — maintain relative spacing and same target aircraft
          if (drag.groupFlights) {
            const anchorWM = weekMins(drag.finalDay, drag.finalDep);
            for (const gf of drag.groupFlights) {
              let gWM = anchorWM + gf.offsetWM;
              if (gWM < 0) gWM += WEEK_MINS;
              if (gWM >= WEEK_MINS) gWM -= WEEK_MINS;
              const gDay = Math.floor(gWM / DAY_MINS) + 1;
              const gDep = Math.round(gWM % DAY_MINS);
              const gUpdate = { id: gf.id, day: gDay, dep: gDep };
              if (targetAc) gUpdate.acId = targetAc.id;
              dispatchRef.current({ type: A.UPDATE_FLIGHT, flight: gUpdate, _noHistory: true });
            }
          }
        }
      }

      // ── Finalise resize: single dispatch ───────────────────────
      if (resizeRef.current && dragEngagedRef.current) {
        dispatchRef.current({ type: A.HISTORY_PUSH });
        dispatchRef.current({
          type: A.UPDATE_FLIGHT,
          flight: { id: resizeRef.current.id, block: resizeRef.current.finalBlock },
          _noHistory: true,
        });
      }

      dragRef.current   = null;
      resizeRef.current = null;
      if (dragActiveRef) dragActiveRef.current = false;
    }

    window.addEventListener("mousemove", onPointerMove);
    window.addEventListener("mouseup",   onPointerUp);
    window.addEventListener("touchmove", onPointerMove, { passive: false });
    window.addEventListener("touchend",  onPointerUp);
    window.addEventListener("touchcancel", onPointerUp);
    return () => {
      window.removeEventListener("mousemove", onPointerMove);
      window.removeEventListener("mouseup",   onPointerUp);
      window.removeEventListener("touchmove", onPointerMove);
      window.removeEventListener("touchend",  onPointerUp);
      window.removeEventListener("touchcancel", onPointerUp);
    };
  }, []);

  return { startDrag, startResize, dragEngagedRef };
}


