// ║  SECTION 5 — ERROR BOUNDARY                                              ║
// ╚═══════════════════════════════════════════════════════════════════════════╝

/** Simple error boundary — catches render crashes per tab */
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }
  render() {
    if (this.state.hasError) {
      return (
        <div style={{
          padding: 48, textAlign: "center", fontFamily: FONT, color: C.danger,
        }}>
          <div style={{ fontSize: 36, marginBottom: 12, opacity: 0.3 }}>⚠︎</div>
          <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 8 }}>
            Something went wrong in this tab
          </div>
          <div style={{ fontSize: 12, color: C.textMuted, maxWidth: 400, margin: "0 auto" }}>
            {this.state.error?.message || "Unknown error"}
          </div>
          <button
            onClick={() => this.setState({ hasError: false, error: null })}
            style={{
              marginTop: 16, background: C.yellowHeavy, color: "#fff",
              border: "none", padding: "8px 20px", borderRadius: 6,
              cursor: "pointer", fontSize: 12, fontFamily: FONT, fontWeight: 600,
            }}
          >
            Try Again
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}


