/** Curfew info banner for edit modals — shows dep/arr windows for origin + destination */
function CurfewInfo({ depApt, arrApt, lookupAirport }) {
  if (!depApt && !arrApt) return null;
  const origAp = depApt ? lookupAirport(depApt) : null;
  const destAp = arrApt ? lookupAirport(arrApt) : null;
  if (!origAp && !destAp) return null;

  const fmtW = (open, close) => {
    if (open == null || close == null) return "24/7";
    return `${toHHMM(open)}–${toHHMM(close)}`;
  };

  const apInfo = (ap) => {
    if (!ap) return null;
    const hasDep = ap.depOpen != null && ap.depClose != null;
    const hasArr = ap.arrOpen != null && ap.arrClose != null;
    const is247 = !hasDep && !hasArr;
    const sameTimes = hasDep && hasArr && ap.depOpen === ap.arrOpen && ap.depClose === ap.arrClose;
    return (
      <span key={ap.code}>
        <span style={{ fontFamily: FONT, fontWeight: 700 }}>{ap.code}</span>
        {" "}
        {is247 ? (
          <span style={{ color: C.success }}>24/7</span>
        ) : sameTimes ? (
          <span>{fmtW(ap.depOpen, ap.depClose)}</span>
        ) : (
          <span>dep {fmtW(ap.depOpen, ap.depClose)} · arr {fmtW(ap.arrOpen, ap.arrClose)}</span>
        )}
        {ap.notes ? <span style={{ color: C.textMuted, fontStyle: "italic" }}> {ap.notes}</span> : null}
      </span>
    );
  };

  const orig = apInfo(origAp);
  const dest = apInfo(destAp);
  if (!orig && !dest) return null;

  return (
    <div style={{
      marginBottom: 8, padding: "4px 8px", borderRadius: 4, fontSize: 9,
      color: C.textSoft, background: C.offWhite, border: `1px solid ${C.brownLight}`,
      display: "flex", flexDirection: "column", gap: 1,
    }}>
      {orig}
      {dest}
    </div>
  );
}

