function MultiDaySelector({ value, onChange, size }) {
  const labels = ["M", "T", "W", "T", "F", "S", "S"];
  const sm = size === "sm";
  const toggle = (d) => {
    const set = new Set(value || []);
    if (set.has(d)) set.delete(d); else set.add(d);
    onChange([...set].sort());
  };
  return (
    <div style={{ display: "flex", gap: sm ? 1 : 3 }}>
      {ALL_DAYS.map(d => {
        const active = (value || []).includes(d);
        return (
          <button
            key={d}
            onClick={() => toggle(d)}
            style={{
              width:        sm ? 16 : 26,
              height:       sm ? 20 : 28,
              borderRadius: sm ? 3 : 5,
              border:       `1.5px solid ${active ? C.yellowHeavy : C.brownLight}`,
              background:   active ? C.yellowLight : C.white,
              color:        active ? C.yellowHeavy : C.brownHeavy,
              cursor:       "pointer",
              fontSize:     sm ? 8 : 10,
              fontFamily:   FONT,
              fontWeight:   600,
              padding:      0,
            }}
          >
            {labels[d - 1]}
          </button>
        );
      })}
    </div>
  );
}

// ── Modal overlay ────────────────────────────────────────────────────────────

function CustomerTagInput({ value, onChange, flights, style: outerStyle = {} }) {
  const [focused, setFocused] = useState(false);
  const [input, setInput] = useState(value || "");
  const ref = useRef(null);

  // Sync external value
  useEffect(() => { setInput(value || ""); }, [value]);

  // Collect unique customers from all flights
  const knownCustomers = useMemo(() => {
    const set = new Set();
    (flights || []).forEach(f => { if (f.customer && f.customer.trim()) set.add(f.customer.trim()); });
    return [...set].sort();
  }, [flights]);

  const filtered = useMemo(() => {
    if (!input.trim()) return knownCustomers.slice(0, 8);
    const q = input.trim().toLowerCase();
    return knownCustomers.filter(c => c.toLowerCase().includes(q) && c.toLowerCase() !== q).slice(0, 6);
  }, [input, knownCustomers]);

  const showDropdown = focused && filtered.length > 0;

  const select = (c) => {
    setInput(c);
    onChange(c);
    setFocused(false);
  };

  return (
    <div style={{ position: "relative", ...outerStyle }}>
      <input
        ref={ref}
        style={{ ...iStyle, width: "100%" }}
        placeholder="e.g. Amazon, DHL, Ceva…"
        value={input}
        onChange={e => { setInput(e.target.value); }}
        onFocus={() => setFocused(true)}
        onBlur={() => { setTimeout(() => setFocused(false), 150); if (input !== (value || "")) onChange(input); }}
        onKeyDown={e => { if (e.key === "Enter") { e.target.blur(); } }}
      />
      {showDropdown && (
        <div style={{
          position: "absolute", top: "100%", left: 0, right: 0, zIndex: 50,
          background: C.white, border: `1px solid ${C.brownLight}`, borderRadius: 6,
          boxShadow: "0 4px 12px rgba(0,0,0,0.1)", maxHeight: 160, overflowY: "auto",
          marginTop: 2,
        }}>
          {filtered.map(c => (
            <div key={c}
              onMouseDown={e => { e.preventDefault(); select(c); }}
              style={{
                padding: "6px 10px", fontSize: 11, cursor: "pointer",
                color: C.text, fontFamily: FONT,
                background: "transparent",
              }}
              onMouseEnter={e => e.currentTarget.style.background = C.offWhite}
              onMouseLeave={e => e.currentTarget.style.background = "transparent"}
            >{c}</div>
          ))}
        </div>
      )}
    </div>
  );
}

function Modal({ title, onClose, children, width = 480 }) {
  useEffect(() => {
    function onKey(e) { if (e.key === "Escape") onClose(); }
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose]);
  return (
    <div
      style={{
        position:       "fixed",
        inset:          0,
        background:     "rgba(17,24,39,0.4)",
        display:        "flex",
        alignItems:     "center",
        justifyContent: "center",
        zIndex:         3000,
        padding:        24,
      }}
      onClick={onClose}
    >
      <div
        style={{
          background:   C.white,
          borderRadius: 12,
          boxShadow:    "0 20px 60px rgba(0,0,0,0.15)",
          padding:      28,
          width:        "100%",
          maxWidth:     width,
          maxHeight:    "90vh",
          overflowY:    "auto",
        }}
        onClick={e => e.stopPropagation()}
      >
        <div
          style={{
            display:        "flex",
            alignItems:     "center",
            justifyContent: "space-between",
            marginBottom:   20,
          }}
        >
          <span style={{ fontSize: 15, fontWeight: 700, color: C.text }}>
            {title}
          </span>
          <button
            onClick={onClose}
            style={{
              background: "none",
              border:     "none",
              cursor:     "pointer",
              color:      C.textMuted,
              fontSize:   20,
              lineHeight: 1,
              padding:    "0 2px",
            }}
          >
            ×
          </button>
        </div>
        {children}
      </div>
    </div>
  );
}


