            <div style={{ display: "flex", gap: 6, marginTop: 6, flexWrap: "wrap" }}>
              {[{ l: "4h", v: 240 }, { l: "8h", v: 480 }, { l: "12h", v: 720 }, { l: "15h", v: 900 }, { l: "24h", v: 1440 }, { l: "48h", v: 2880 }].map(p => (
                <button key={p.v} onClick={() => setMxEditModal({ ...mxEditModal, duration: p.v })}
                  style={{
                    padding: "3px 10px", borderRadius: 4, cursor: "pointer",
                    fontSize: 9, fontFamily: FONT, fontWeight: mxEditModal.duration === p.v ? 700 : 500,
                    background: mxEditModal.duration === p.v ? C.yellowHeavy : "transparent",
                    color: mxEditModal.duration === p.v ? "#FFFFFF" : C.textSoft,
                    border: `1px solid ${mxEditModal.duration === p.v ? C.yellowHeavy : C.brownLight}`,
                  }}>{p.l}</button>
              ))}
            </div>
